// ── Node 2: Parse Form & Normalize Binary ─────────────────────────
// Input:  1 item from Form Trigger with multiple files in binary
// Output: N items (1 per uploaded file), each with json metadata + binary.data

const form = $input.first().json;
const binaryData = $input.first().binary;

// ── Build metadata ──
const folderName = `${new Date().toISOString().replace(/[-:T]/g, '').slice(0, 14)}_${(form.projectTitle || 'untitled').replace(/[^a-zA-Z0-9]/g, '_').slice(0, 30)}`;
const basePath = `/data/confidential/${folderName}`;

const category = Array.isArray(form.category)
  ? form.category.join(',')
  : (form.category || '');

const consentGiven = Array.isArray(form.confidentialityConsent)
  ? form.confidentialityConsent.includes('True')
  : form.confidentialityConsent === true || form.confidentialityConsent === 'true';

const metadata = {
  folder_name: folderName,
  base_path: basePath,
  project_title: form.projectTitle || '',
  primary_inventors: form.primaryInventors || '',
  category: category,
  description: form.description || '',
  services: form.services || '',
  consent_given: consentGiven,
  submission_timestamp: new Date().toISOString(),
  workflow_version: '1.0',
};

// ── Split: 1 item with N binaries → N items, 1 binary each ──
const binaryKeys = Object.keys(binaryData || {});

if (binaryKeys.length === 0) {
  throw new Error('No files were uploaded. At least one file is required.');
}

return binaryKeys.map((key) => {
  const bin = binaryData[key];
  return {
    json: {
      ...metadata,
      file_name: bin.fileName || bin.filename || key,
      file_count: binaryKeys.length,
    },
    binary: { data: bin },
  };
});

// ── Node 3: Create Folder Structure ───────────────────────────────
// Uses fs.mkdirSync with recursive:true — idempotent, safe to re-run

const fs = require('fs');
const path = require('path');

const items = $input.all();
const results = [];

for (const item of items) {
  const basePath = item.json.base_path;

  const dirs = [
    path.join(basePath, '00_Admin'),
    path.join(basePath, '01_Original'),
    path.join(basePath, '02_Redacted'),
    path.join(basePath, '03_Assessment'),
  ];

  for (const dir of dirs) {
    fs.mkdirSync(dir, { recursive: true });
  }

  results.push(item);  // Pass through unchanged
}

return results;

// ── Node 5a: Build submission_info.json Binary ─────────────────────
// Input:  N items (all with same metadata)
// Output: 1 item with binary.data = the JSON file content

const first = $input.first();

const info = {
  project_title: first.json.project_title,
  primary_inventors: first.json.primary_inventors,
  category: first.json.category,
  description: first.json.description,
  consent_given: first.json.consent_given,
  submission_timestamp: first.json.submission_timestamp,
  workflow_version: first.json.workflow_version,
  file_count: first.json.file_count,
  files: $input.all().map((item) => item.json.file_name),
};

const jsonStr = JSON.stringify(info, null, 2);

return [{
  json: {
    base_path: first.json.base_path,
  },
  binary: {
    data: await this.helpers.prepareBinaryData(
      Buffer.from(jsonStr, 'utf-8'),
      'submission_info.json',
      'application/json'
    ),
  },
}];

const binary = items[0].binary.data;
const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
const base64Image = buffer.toString('base64');

return [{
  json: {
    base64Image: base64Image,
    mimeType: 'image/jpeg',
    fileName: binary.fileName || 'image.jpg',
    base_path: items[0].json.base_path,
    folder_name: items[0].json.folder_name,
    project_title: items[0].json.project_title
  }
}];

