const loopData = $('Loop Over Images').first().json;
// Access the first incoming item using modern n8n syntax
const httpResult = $input.first().json

return [{
  json: {
    // Original image info (preserved)
    fileName: loopData.fileName,
    base_path: loopData.base_path,
    // LLM analysis result
    description: httpResult.choices[0].message.content
  }}];

const rawText = $input.first().json.files[0].text

// Clean the text: replace newlines and control characters
const cleanedText = rawText
  .replace(/\r\n|\r|\n/g, ' ')           // Replace all line breaks with space
  .replace(/\t/g, ' ')                   // Replace tabs
  .replace(/[\x00-\x1F\x7F]/g, ' ')      // Remove other control characters
  .replace(/([a-z])([A-Z])/g, '$1 $2')   // Add space between lowercase and uppercase (helloWorld → hello World)
  .replace(/\s+/g, ' ')                  // Normalize multiple spaces
  .trim();

return [
  {
    json: {
      fileName: $input.first().json.files[0].metadata.fileName,
      fileType: $input.first().json.files[0].metadata.fileType,
      cleanedText: cleanedText
    }
  }
];

const fs = require('fs');
const path = require('path');

// === DYNAMIC PATH CONFIGURATION ===
const analyses = $input.first().json.analyses || [];

if (!analyses.length) {
  throw new Error('No analyses found in input JSON. Cannot determine base_path.');
}

const basePath = analyses[0].base_path || '/tmp/fallback';
const outputDir = path.join(basePath, '02_Redacted');   // ← YOUR REQUIRED PATH
// ===================================

const today = new Date().toISOString().split('T')[0];
const projectFolder = basePath.split('/').pop(); // e.g. Project_20260608073356_asd

// === BUILD RICH MARKDOWN (workflow-ready) ===
let md = `# Image Analysis Report\n\n`;
md += `**Generated:** ${today}  \n`;
md += `**Source:** n8n LLM Vision Analysis  \n`;
md += `**Context:** AI Automation Tool – PI document processing & KTH Innovation Readiness Level (IRL) assessment\n\n`;
md += `---\n\n`;

md += `## Executive Summary for Technology Assessment Officer Review\n`;
md += `This consolidated markdown dossier contains LLM-generated descriptions of all visual assets (figures/slides) from the project folder. `;
md += `It is structured for direct ingestion into the **KTH IRL 6-pillar scoring sheet**, **TT&E Framework** (Maturity Delta & Translation Risk Coefficient ρ), and investor framing workflows (UR7).\n\n`;
md += `**Recommended immediate actions:**\n`;
md += `1. Feed this file into the downstream KTH IRL auto-scoring node.\n`;
md += `2. Review TRL signals visible in the experimental/CFD data.\n`;
md += `3. Prioritise CRL activities (customer discovery) before further technology push.\n\n`;
md += `---\n\n`;

analyses.forEach((item, idx) => {
  md += `## ${idx + 1}. ${item.fileName}\n\n`;
  md += `**File Name:** ${item.fileName}  \n`;
  md += `**Analysis Type:** LLM Vision Description\n\n`;
  md += `**Description:**\n\n${item.description}\n\n`;
  md += `---\n\n`;
});

// === WRITE TO {base_path}/02_Redacted ===
fs.mkdirSync(outputDir, { recursive: true });

const safeFileName = `Image_Analysis_${projectFolder}_${today}.md`;
const outputPath = path.join(outputDir, safeFileName);

fs.writeFileSync(outputPath, md, 'utf8');

return [{
  json: {
    success: true,
    filePath: outputPath,
    fileName: safeFileName,
    numFigures: analyses.length,
    basePath: basePath,
    redactedFolder: outputDir,
    message: `Markdown successfully written to ${outputDir}`
  }
}];

function detectLanguage(text) {
  const t = text || "";
  const cjk = (t.match(/[\u4e00-\u9fff]/g) || []).length;
  const latin = (t.match(/[A-Za-z]/g) || []).length;
  const len = Math.max(t.length, 1);

  const cjkRatio = cjk / len;
  const latinRatio = latin / len;

  // Tune thresholds with your real docs
  if (cjkRatio > 0.08 && latinRatio > 0.08) return "mixed";
  if (cjkRatio > 0.10) return "zh";
  return "en";
}

const cleanedText = $input.first().json.cleanedText || "";
return [{ json: { cleanedText, language: detectLanguage(cleanedText) } }];

