{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "title": "Market Research Report Output Schema v5",
  "description": "Structured output schema for the Market Research Agent (v5 — evidence-first). Every quantitative claim, market figure, projection, or factual assertion MUST include an inline source citation with a directly accessible URL. Unverifiable claims MUST NOT be included.",
  "type": "object",
  "properties": {
    "executive_summary": {
      "type": "array",
      "description": "4-6 high-level headline paragraphs. Each string is one paragraph (no label prefix). CRITICAL: every paragraph that contains any quantitative claim, market figure, projection, or factual assertion MUST end with an inline source citation using the format [Organization, Year](URL). Example: 'The global 6G market is projected to reach $40-50B by 2035. [MarketsandMarkets, 2025](https://www.marketsandmarkets.com/Market-Reports/6g-market-123.html)' If a paragraph makes no quantitative claims, a citation is optional but still preferred.",
      "items": { "type": "string" },
      "minItems": 3
    },

    "market_sizing": {
      "type": "object",
      "description": "Market sizing and opportunity analysis. EVERY number, estimate, CAGR, dollar figure, and projection MUST have an inline source citation. Do NOT include any figure you cannot substantiate with a real, accessible source.",
      "properties": {
        "tam": {
          "type": "string",
          "description": "Total Addressable Market — MUST include dollar value, year, CAGR with source, and at least one inline citation with full URL. MANDATORY FORMAT: '...$X by Year, growing at Y% CAGR [Organization, Report Title, Year](https://exact-url-to-report-page)'. Every figure in this field requires its own citation. If you cannot find a reliable recent source, write 'No reliable recent TAM data found as of [today's date]' instead of fabricating a number."
        },
        "sam": {
          "type": "string",
          "description": "Serviceable Addressable Market — MUST include dollar value, year, geographic/segment split with at least one inline citation. Same citation format as TAM. If no reliable data, state the limitation explicitly."
        },
        "som": {
          "type": "string",
          "description": "Serviceable Obtainable Market — MUST include dollar value, 5-year target, capture % with assumptions clearly stated. Cite any comparable licensing deals, spinout revenues, or industry benchmarks used to derive the SOM. If derived purely from assumptions without external benchmarks, state 'SOM is an estimate based on the following assumptions: ... (no external benchmark found)'."
        },
        "market_drivers": {
          "type": "array",
          "description": "List of market drivers — each string is one driver. CRITICAL: any driver that includes a quantitative claim (budget, growth rate, adoption figure, policy amount) MUST include an inline citation. Non-quantitative drivers (e.g., 'growing demand for higher bandwidth') do not require citations but should still be grounded in the research. Example with citation: 'US CHIPS and Science Act allocates $52.7B for semiconductor R&D. [US Congress, CHIPS and Science Act, 2022](https://www.congress.gov/bill/117th-congress/senate-bill/2756)'",
          "items": { "type": "string" }
        },
        "advantages_vs_alternatives": {
          "type": "array",
          "description": "Competitive advantages of this technology vs alternative solutions. Each advantage should be specific and evidence-based. If referencing a performance comparison, benchmark, or test result, cite the source.",
          "items": { "type": "string" }
        },
        "disadvantages_and_risks": {
          "type": "array",
          "description": "Disadvantages and risks of this technology (not project-level risks — those go in the 'risks' section). Cite sources for any specific technical limitations, cost comparisons, or market barriers referenced.",
          "items": { "type": "string" }
        },
        "cost_structure": {
          "type": "string",
          "description": "R&D costs, unit economics at scale, gross margin potential. Any cost figures or margin estimates MUST be cited. If no specific data found, state the limitation."
        },
        "entry_barriers": {
          "type": "array",
          "description": "Barriers to entry for new competitors. Cite sources for any regulatory requirements, capital thresholds, or IP landscape claims.",
          "items": { "type": "string" }
        }
      },
      "required": ["tam", "sam", "som", "market_drivers", "advantages_vs_alternatives", "disadvantages_and_risks"]
    },

    "ecosystem_positioning": {
      "type": "object",
      "description": "Ecological niche and ecosystem positioning analysis. Include inline citations for any referenced partnerships, market positions, or industry data.",
      "properties": {
        "value_chain_position": {
          "type": "string",
          "description": "Where in the value chain the project sits, plus business model options. Cite any industry reports or analyses referenced."
        },
        "business_cycle_stage": {
          "type": "string",
          "description": "Current stage of the market/business cycle and timing implications. Cite any market maturity assessments or analyst reports referenced."
        },
        "complementors_and_partners": {
          "type": "array",
          "description": "Complementary players and potential partners. If referencing a specific partnership, collaboration, or integration, cite the source.",
          "items": { "type": "string" }
        },
        "substitutes_and_alternatives": {
          "type": "array",
          "description": "Substitute technologies and alternative solutions. Cite performance comparisons or market share data where referenced.",
          "items": { "type": "string" }
        },
        "platform_and_ecosystem_dynamics": {
          "type": "string",
          "description": "Platform play potential and cross-vertical licensing opportunities."
        },
        "white_space_opportunities": {
          "type": "array",
          "description": "Adjacent market white-space opportunities. Cite any market gap analyses or unmet need assessments referenced.",
          "items": { "type": "string" }
        },
        "business_model_implications": {
          "type": "string",
          "description": "Recommended business model structure (licensing, JDA, spinout) with economics. Cite any comparable deal structures or revenue models referenced."
        }
      },
      "required": ["value_chain_position", "business_cycle_stage", "complementors_and_partners", "substitutes_and_alternatives", "business_model_implications"]
    },

    "competitive_landscape": {
      "type": "object",
      "description": "Competitive and alternatives analysis. CRITICAL: every competitor entry MUST cite a real, accessible source URL (company page, product page, press release, patent, or news article). Do NOT list competitors without evidence of their existence and activities.",
      "properties": {
        "academic_competitors": {
          "type": "array",
          "description": "Academic/research competitors — each string MUST name the institution, group, focus area, TRL if known, AND include an inline citation with a direct URL to the research group page, specific paper (DOI or arXiv), or press release. Example: 'University of Birmingham (UK): High-performance THz slotted waveguide antenna, gain 6.7→10.1 dB. [Birmingham THz Group](https://www.birmingham.ac.uk/research/activity/eee/communications/thz.aspx)' Do NOT fabricate competitors or performance figures.",
          "items": { "type": "string" }
        },
        "industry_competitors": {
          "type": "array",
          "description": "Industry competitors — each string MUST name the company, approach, and include an inline citation with a direct URL to the company's product page, press release, SEC filing, or news article. Include R&D budget or funding only if sourced from SEC filings, press releases, or credible databases. Example: 'Kymeta Corporation (US): Liquid crystal metasurface flat-panel antennas for Ku/Ka-band satellite. [Kymeta u8 Product Page](https://kymetacorp.com/products/u8-terminal)' Do NOT fabricate companies, products, or funding amounts.",
          "items": { "type": "string" }
        },
        "indirect_competitors": {
          "type": "array",
          "description": "Indirect competitors and alternative solutions. Cite sources where possible.",
          "items": { "type": "string" }
        },
        "positioning_gaps_and_exploitable_weaknesses": {
          "type": "array",
          "description": "Gaps in competitors' positioning that this project can exploit. Base each gap on specific evidence from the competitor's public information or cited sources.",
          "items": { "type": "string" }
        },
        "defensibility_signals": {
          "type": "array",
          "description": "Signals that defend the project's competitive position (IP, awards, novel architecture, etc.). Cite the specific patent, award, or publication where possible. Example: 'Gold Medal at 48th International Exhibition of Inventions Geneva. [IEIG](https://www.inventions-geneva.ch)'",
          "items": { "type": "string" }
        },
        "competitive_response_risks": {
          "type": "array",
          "description": "Risks of competitive response (design-around, acquisition, faster followers). Cite any specific competitive moves or industry trends referenced.",
          "items": { "type": "string" }
        },
        "go_to_market_comparison": {
          "type": "string",
          "description": "Comparison of competitors' GTM approach vs the project's recommended approach. Cite sources for competitor GTM strategies referenced."
        }
      },
      "required": ["academic_competitors", "industry_competitors", "indirect_competitors", "positioning_gaps_and_exploitable_weaknesses", "defensibility_signals"]
    },

    "investor_and_funding_framing": {
      "type": "object",
      "description": "Investor framing. CRITICAL: every funding amount, valuation, comparable transaction, and check size MUST cite a real source (Crunchbase, PitchBook, SEC filing, press release, or official announcement). Do NOT fabricate funding rounds or valuations.",
      "properties": {
        "why_now": {
          "type": "array",
          "description": "Reasons why this is the right time to invest. Each reason that references a specific policy, funding program, market event, or data point MUST include an inline citation. Example: 'EU Horizon Europe 2026 work programme allocates €320M to smart networks. [European Commission, 2026](https://ec.europa.eu/info/funding/tenders/horizon/eu)'",
          "items": { "type": "string" }
        },
        "key_value_drivers": {
          "type": "array",
          "description": "Value drivers that make this attractive to investors. Cite evidence for any specific metrics or market data referenced.",
          "items": { "type": "string" }
        },
        "risks_from_investor_perspective": {
          "type": "array",
          "description": "Risks as viewed from an investor's lens (technology, market timing, competitive, standards, IP, team).",
          "items": { "type": "string" }
        },
        "comparable_transactions": {
          "type": "array",
          "description": "Comparable funding rounds, acquisitions, IPOs with valuations. CRITICAL: every transaction MUST include amount, date/year, and an inline citation with URL to the announcement, SEC filing, Crunchbase, or credible news source. Example: 'Teradar raised $150M Series B in 2025 for THz vision sensors. [TechCrunch](https://techcrunch.com/2025/03/teradar-series-b)' Do NOT fabricate transactions.",
          "items": { "type": "string" }
        },
        "investor_profiles_and_check_sizes": {
          "type": "array",
          "description": "Investor types (deep tech VC, corporate VC, grants) with typical check sizes. Cite any specific fund sizes, investment thesis pages, or portfolio data referenced.",
          "items": { "type": "string" }
        },
        "likely_investor_questions": {
          "type": "array",
          "description": "Likely investor due diligence questions and red flags.",
          "items": { "type": "string" }
        }
      },
      "required": ["why_now", "key_value_drivers", "risks_from_investor_perspective", "investor_profiles_and_check_sizes"]
    },

    "promotion_ready_messaging": {
      "type": "object",
      "description": "Ready-to-use promotional copy. Separated from investor framing so it can be rendered as distinct quote callouts.",
      "properties": {
        "for_pitches": {
          "type": "string",
          "description": "1-3 sentence promotional copy suitable for investor pitches. Should be punchy and self-contained. No citations needed here — this is polished copy, not a claim."
        },
        "for_grant_applications": {
          "type": "string",
          "description": "1-3 sentence promotional copy suitable for grant applications. Should emphasize alignment with strategic priorities. No citations needed here — this is polished copy, not a claim."
        }
      },
      "required": ["for_pitches", "for_grant_applications"]
    },

    "implications_and_actionable_recommendations": {
      "type": "array",
      "description": "Actionable recommendations, each with an explicit phase and timeframe. Recommendations should follow logically from the cited evidence above.",
      "items": {
        "type": "object",
        "properties": {
          "phase": {
            "type": "string",
            "enum": [
              "immediate",
              "short_term",
              "medium_term",
              "long_term",
              "risk_mitigation",
              "investor_readiness"
            ],
            "description": "Execution phase. immediate=0-6mo, short_term=6-18mo, medium_term=18-36mo, long_term=36-60mo, risk_mitigation=ongoing, investor_readiness=now."
          },
          "timeframe": {
            "type": "string",
            "description": "Human-readable timeframe, e.g. '0-6 months' or 'Ongoing'."
          },
          "action": {
            "type": "string",
            "description": "The recommendation itself — specific, actionable, with cost/owner/timeline where possible."
          }
        },
        "required": ["phase", "timeframe", "action"]
      },
      "minItems": 3
    },

    "risks": {
      "type": "array",
      "description": "Risk inventory — each risk has an explicit title and severity.",
      "items": {
        "type": "object",
        "properties": {
          "title": {
            "type": "string",
            "description": "Short risk title, e.g. 'Technology Risk', 'Market Timing Risk', 'IP Risk'."
          },
          "severity": {
            "type": "string",
            "enum": ["high", "medium_high", "medium", "medium_low", "low"],
