// =============================================
// Market Research Report Generator (v4.1 — Inline Source Links, Layout Fixes)
// 
// MAJOR CHANGES FROM v3:
// - Inline source links: [text](url) and legacy [domain] patterns in body text
//   are now rendered as clickable links directly where the claim is made, instead
//   of a separate "Sources" section at the bottom.
// - New formatBody() function replaces formatBold() for all body content — it
//   handles [text](full-url), legacy [domain], and **bold** patterns.
// - Removed: formatSource(), categorizeSource(), sourcesByCategory, the entire
//   Sources section from the HTML template, and the "Sources" nav link.
// - The "sources" field in the JSON schema is still ingested (kept in normalize)
//   but no longer rendered as a separate section. All source links are inline.
// - Backward compatible: if the LLM still outputs [domain] format, those are
//   converted to inline links pointing to https://domain.
// =============================================

const basepath = $('Parse Form & Normalize Binary').first().json.base_path;
const marketData = items[0].json.output || items[0].json;
const filePath = `${basepath}/03_Assessment/Market_Research_Report.html`;

const today = new Date().toISOString().slice(0, 10);

// =============================================
// Helper Functions
// =============================================

function escapeHtml(text) {
    if (!text) return '';
    return text
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;');
}

function formatBold(text) {
    if (!text) return '';
    return escapeHtml(text).replace(/\*\*(.*?)\*\*/g, '<strong class="font-semibold text-slate-900">$1</strong>');
}

// --- v4.1: formatBody() with paren-safe markdown link extraction ---
// Handles inline source links [text](url) and legacy [domain] plus **bold**.
// Used for ALL body content throughout the report.
//
// FIX: The original regex [^)]+ stopped at the first ')' in the URL,
//      breaking links like .../file(2024)rest.pdf . Now uses a
//      paren-depth-aware parser that handles nested parentheses per
//      the CommonMark balanced-paren rule for link destinations.

function extractMarkdownLinks(text) {
    const links = [];
    let result = '';
    let i = 0;
    while (i < text.length) {
        if (text[i] === '[') {
            const bracketEnd = text.indexOf(']', i);
            if (bracketEnd !== -1 && bracketEnd - i > 0 && text[bracketEnd + 1] === '(') {
                const linkText = text.substring(i + 1, bracketEnd);
                let depth = 0;
                let j = bracketEnd + 2; // skip past '('
                while (j < text.length) {
                    if (text[j] === '(') { depth++; }
                    else if (text[j] === ')') {
                        if (depth === 0) break; // closing paren of the link
                        depth--;
                    }
                    j++;
                }
                if (j < text.length && text[j] === ')') {
                    const url = text.substring(bracketEnd + 2, j).trim();
                    if (url.length > 0) {
                        const idx = links.length;
                        links.push({ text: linkText, url: url });
                        result += `__INLINESRC_${idx}__`;
                        i = j + 1;
                        continue;
                    }
                }
            }
        }
        result += text[i];
        i++;
    }
    return { text: result, links };
}

function formatBody(text) {
    if (!text) return '';

    // Step 1: Extract [text](url) markdown links (paren-depth-aware)
    //         BEFORE html escaping so the URL is preserved intact.
    let { text: processed, links } = extractMarkdownLinks(text);

    // Step 2: Extract legacy [domain.com] patterns (bare domain in brackets,
    //         not already consumed by Step 1 which requires "(url)" suffix).
    let allLinks = [...links]; // carry forward already-extracted links
    processed = processed.replace(/\[([a-zA-Z0-9][a-zA-Z0-9.-]*\.[a-zA-Z]{2,})\]/g, (_match, domain) => {
        const idx = allLinks.length;
        const url = domain.startsWith('http') ? domain : `https://${domain}`;
        allLinks.push({ text: domain, url: url });
        return `__INLINESRC_${idx}__`;
    });

    // Step 3: HTML-escape the remaining text
    processed = escapeHtml(processed);

    // Step 4: Restore extracted links as <a> tags
    processed = processed.replace(/__INLINESRC_(\d+)__/g, (_match, idxStr) => {
        const link = allLinks[parseInt(idxStr, 10)];
        const safeUrl = escapeHtml(link.url);
        const safeText = escapeHtml(link.text);
        return `<a href="${safeUrl}" target="_blank" rel="noopener noreferrer" class="inline-src" title="${safeUrl}">${safeText} <i class="fa-solid fa-arrow-up-right-from-square text-[9px] opacity-60"></i></a>`;
    });

    // Step 5: Convert **bold** to <strong>
    processed = processed.replace(/\*\*(.*?)\*\*/g, '<strong class="font-semibold text-slate-900">$1</strong>');

    return processed;
}

// Split "Label: body" — only treat as label if colon appears in first 80 chars
function splitLabelBody(text) {
    if (!text) return { label: null, body: '' };
    const colonIdx = text.indexOf(':');
    if (colonIdx === -1 || colonIdx > 80) {
        return { label: null, body: text };
    }
    return {
        label: text.substring(0, colonIdx).trim(),
        body: text.substring(colonIdx + 1).trim()
    };
}

// Legacy parsers — only used when input is in the old flat-string format
function parseRecommendationPhase_legacy(text) {
    const match = text.match(/^(IMMEDIATE|SHORT-TERM|MEDIUM-TERM|LONG-TERM|RISK MITIGATION|INVESTOR READINESS)\s*(?:\(([^)]+)\))?:\s*([\s\S]*)/);
    if (match) {
        const phaseMap = {
            'IMMEDIATE': 'immediate', 'SHORT-TERM': 'short_term', 'MEDIUM-TERM': 'medium_term',
            'LONG-TERM': 'long_term', 'RISK MITIGATION': 'risk_mitigation', 'INVESTOR READINESS': 'investor_readiness'
        };
        return { phase: phaseMap[match[1]], timeframe: match[2] || '', action: match[3].trim() };
    }
    return { phase: 'other', timeframe: '', action: text };
}

function parseRiskItem_legacy(text) {
    const riskMatch = text.match(/^([A-Z][A-Z\s\/]+?)\s*\((High|Medium-High|Medium|Medium-Low|Low)\):\s*([\s\S]*)/);
    if (riskMatch) {
        const sevMap = { 'High': 'high', 'Medium-High': 'medium_high', 'Medium': 'medium', 'Medium-Low': 'medium_low', 'Low': 'low' };
        return { type: 'risk', title: riskMatch[1].trim(), severity: sevMap[riskMatch[2]], description: riskMatch[3].trim() };
    }
    const contrarianMatch = text.match(/^(CONTRARIAN VIEW\s*\d+):\s*([\s\S]*)/i);
    if (contrarianMatch) {
        return { type: 'contrarian', title: contrarianMatch[1].toUpperCase(), view: contrarianMatch[2].trim(), implication: '', counter_argument: '' };
    }
    if (text.toUpperCase().startsWith('DATA STALENESS WARNING:')) {
        return { type: 'warning', body: text.substring('DATA STALENESS WARNING:'.length).trim() };
    }
    return { type: 'risk', title: 'Risk', severity: 'medium', description: text };
}

function severityBadge(severity) {
    const map = {
        'high':         { cls: 'bg-red-100 text-red-700 border-red-200',         icon: 'fa-circle-exclamation',   dot: 'bg-red-500',     label: 'HIGH' },
        'medium_high':  { cls: 'bg-orange-100 text-orange-700 border-orange-200', icon: 'fa-triangle-exclamation', dot: 'bg-orange-500',  label: 'MEDIUM-HIGH' },
        'medium':       { cls: 'bg-amber-100 text-amber-700 border-amber-200',   icon: 'fa-circle-exclamation',   dot: 'bg-amber-500',   label: 'MEDIUM' },
        'medium_low':   { cls: 'bg-yellow-100 text-yellow-700 border-yellow-200', icon: 'fa-info-circle',          dot: 'bg-yellow-500',   label: 'MEDIUM-LOW' },
        'low':          { cls: 'bg-emerald-100 text-emerald-700 border-emerald-200', icon: 'fa-circle-check',      dot: 'bg-emerald-500', label: 'LOW' }
    };
    return map[severity] || map['medium'];
}

// Color theming — pre-built class strings so Tailwind CDN picks them up
const COLOR = {
    blue:    { bg50:'bg-blue-50',    bg100:'bg-blue-100',    bg500:'bg-blue-500',    bg600:'bg-blue-600',    text600:'text-blue-600',    text700:'text-blue-700',    text900:'text-blue-900',    border200:'border-blue-200',    border400:'border-blue-400',    ring:'ring-blue-200' },
    emerald: { bg50:'bg-emerald-50', bg100:'bg-emerald-100', bg500:'bg-emerald-500', bg600:'bg-emerald-600', text600:'text-emerald-600', text700:'text-emerald-700', text900:'text-emerald-900', border200:'border-emerald-200', border400:'border-emerald-400', ring:'ring-emerald-200' },
    amber:   { bg50:'bg-amber-50',   bg100:'bg-amber-100',   bg500:'bg-amber-500',   bg600:'bg-amber-600',   text600:'text-amber-600',   text700:'text-amber-700',   text900:'text-amber-900',   border200:'border-amber-200',   border400:'border-amber-400',   ring:'ring-amber-200' },
    violet:  { bg50:'bg-violet-50',  bg100:'bg-violet-100',  bg500:'bg-violet-500',  bg600:'bg-violet-600',  text600:'text-violet-600',  text700:'text-violet-700',  text900:'text-violet-900',  border200:'border-violet-200',  border400:'border-violet-400',  ring:'ring-violet-200' },
    rose:    { bg50:'bg-rose-50',    bg100:'bg-rose-100',    bg500:'bg-rose-500',    bg600:'bg-rose-600',    text600:'text-rose-600',    text700:'text-rose-700',    text900:'text-rose-900',    border200:'border-rose-200',    border400:'border-rose-400',    ring:'ring-rose-200' },
    red:     { bg50:'bg-red-50',     bg100:'bg-red-100',     bg500:'bg-red-500',     bg600:'bg-red-600',     text600:'text-red-600',     text700:'text-red-700',     text900:'text-red-900',     border200:'border-red-200',     border400:'border-red-400',     ring:'ring-red-200' },
    orange:  { bg50:'bg-orange-50',  bg100:'bg-orange-100',  bg500:'bg-orange-500',  bg600:'bg-orange-600',  text600:'text-orange-600',  text700:'text-orange-700',  text900:'text-orange-900',  border200:'border-orange-200',  border400:'border-orange-400',  ring:'ring-orange-200' },
    slate:   { bg50:'bg-slate-50',   bg100:'bg-slate-100',   bg500:'bg-slate-500',   bg600:'bg-slate-600',   text600:'text-slate-600',   text700:'text-slate-700',   text900:'text-slate-900',   border200:'border-slate-200',   border400:'border-slate-400',   ring:'ring-slate-200' },
    teal:    { bg50:'bg-teal-50',    bg100:'bg-teal-100',    bg500:'bg-teal-500',    bg600:'bg-teal-600',    text600:'text-teal-600',    text700:'text-teal-700',    text900:'text-teal-900',    border200:'border-teal-200',    border400:'border-teal-400',    ring:'ring-teal-200' },
};

// =============================================
// NORMALIZE: convert new structured schema OR legacy flat-string format
// into a single canonical shape used by the HTML generator.
// =============================================

function detectFormat(data) {
    if (typeof data.market_sizing === 'object' && !Array.isArray(data.market_sizing) && data.market_sizing !== null) return 'new';
    if (Array.isArray(data.risks) && data.risks.length > 0 && typeof data.risks[0] === 'object' && data.risks[0].title) return 'new';
    if (typeof data.promotion_ready_messaging === 'object' && data.promotion_ready_messaging !== null) return 'new';
    if (Array.isArray(data.contrarian_views)) return 'new';
    return 'legacy';
}

function normalize(data) {
    const format = detectFormat(data);
    const out = {
        format,
        executive_summary: [],
        market_sizing: {
            tam: '', sam: '', som: '',
            market_drivers: [], advantages_vs_alternatives: [], disadvantages_and_risks: [],
            cost_structure: '', entry_barriers: []
        },
        ecosystem_positioning: {
            value_chain_position: '', business_cycle_stage: '',
            complementors_and_partners: [], substitutes_and_alternatives: [],
            platform_and_ecosystem_dynamics: '', white_space_opportunities: [],
            business_model_implications: ''
        },
        competitive_landscape: {
            academic_competitors: [], industry_competitors: [], indirect_competitors: [],
            positioning_gaps_and_exploitable_weaknesses: [], defensibility_signals: [],
            competitive_response_risks: [], go_to_market_comparison: ''
        },
        investor_and_funding_framing: {
            why_now: [], key_value_drivers: [], risks_from_investor_perspective: [],
            comparable_transactions: [], investor_profiles_and_check_sizes: [],
            likely_investor_questions: []
        },
        promotion_ready_messaging: { for_pitches: '', for_grant_applications: '' },
        recommendations: [],
        risks: [],
        contrarian_views: [],
        data_staleness_warning: '',
        sources: []
    };

    if (format === 'new') {
        // ----- NEW STRUCTURED FORMAT -----
        out.executive_summary = data.executive_summary || [];

        const ms = data.market_sizing || {};
        out.market_sizing = {
            tam: ms.tam || '',
            sam: ms.sam || '',
            som: ms.som || '',
            market_drivers: ms.market_drivers || [],
            advantages_vs_alternatives: ms.advantages_vs_alternatives || [],
            disadvantages_and_risks: ms.disadvantages_and_risks || [],
            cost_structure: ms.cost_structure || '',
            entry_barriers: ms.entry_barriers || []
        };

        const eco = data.ecosystem_positioning || {};
        out.ecosystem_positioning = {
            value_chain_position: eco.value_chain_position || '',
            business_cycle_stage: eco.business_cycle_stage || '',
            complementors_and_partners: eco.complementors_and_partners || [],
            substitutes_and_alternatives: eco.substitutes_and_alternatives || [],
            platform_and_ecosystem_dynamics: eco.platform_and_ecosystem_dynamics || '',
            white_space_opportunities: eco.white_space_opportunities || [],
            business_model_implications: eco.business_model_implications || ''
        };

        const comp = data.competitive_landscape || {};
        out.competitive_landscape = {
            academic_competitors: comp.academic_competitors || [],
            industry_competitors: comp.industry_competitors || [],
            indirect_competitors: comp.indirect_competitors || [],
            positioning_gaps_and_exploitable_weaknesses: comp.positioning_gaps_and_exploitable_weaknesses || [],
            defensibility_signals: comp.defensibility_signals || [],
            competitive_response_risks: comp.competitive_response_risks || [],
            go_to_market_comparison: comp.go_to_market_comparison || ''
        };

        const inv = data.investor_and_funding_framing || {};
        out.investor_and_funding_framing = {
            why_now: inv.why_now || [],
            key_value_drivers: inv.key_value_drivers || [],
            risks_from_investor_perspective: inv.risks_from_investor_perspective || [],
            comparable_transactions: inv.comparable_transactions || [],
            investor_profiles_and_check_sizes: inv.investor_profiles_and_check_sizes || [],
            likely_investor_questions: inv.likely_investor_questions || []
        };

        const prm = data.promotion_ready_messaging || {};
        out.promotion_ready_messaging = {
            for_pitches: prm.for_pitches || '',
            for_grant_applications: prm.for_grant_applications || ''
        };

        // Recommendations — already structured {phase, timeframe, action}
        out.recommendations = (data.implications_and_actionable_recommendations || []).map(r => ({
            phase: r.phase || 'other',
            timeframe: r.timeframe || '',
            action: r.action || ''
        }));

        // Risks — already structured {title, severity, description}
        out.risks = (data.risks || []).map(r => ({
            title: r.title || 'Risk',
            severity: r.severity || 'medium',
            description: r.description || ''
        }));

        // Contrarian views — already structured {title, view, implication, counter_argument}
        out.contrarian_views = (data.contrarian_views || []).map(cv => ({
            title: cv.title || 'Contrarian View',
            view: cv.view || '',
            implication: cv.implication || '',
            counter_argument: cv.counter_argument || ''
        }));

        out.data_staleness_warning = data.data_staleness_warning || '';
        out.sources = data.sources || [];

    } else {
        // ----- LEGACY FLAT-STRING FORMAT -----
        out.executive_summary = data.executive_summary || [];

        const kf = data.key_findings || {};
        const ms = kf.market_sizing_and_opportunity || [];
        ms.forEach(item => {
            const { label, body } = splitLabelBody(item);
            if (!label) return;
            const l = label.toLowerCase();
            if (l.startsWith('tam')) out.market_sizing.tam = body;
            else if (l.startsWith('sam')) out.market_sizing.sam = body;
            else if (l.startsWith('som')) out.market_sizing.som = body;
            else if (l.startsWith('market drivers')) out.market_sizing.market_drivers.push(body);
            else if (l.startsWith('advantages')) out.market_sizing.advantages_vs_alternatives.push(body);
            else if (l.startsWith('disadvantages')) out.market_sizing.disadvantages_and_risks.push(body);
            else if (l.startsWith('cost structure')) out.market_sizing.cost_structure = body;
            else if (l.startsWith('entry barriers')) out.market_sizing.entry_barriers.push(body);
        });

        const eco = kf.ecological_niche_and_ecosystem_positioning || [];
        eco.forEach(item => {
            const { label, body } = splitLabelBody(item);
            if (!label) return;
            const l = label.toLowerCase();
            if (l.startsWith('value chain')) out.ecosystem_positioning.value_chain_position = body;
            else if (l.startsWith('business cycle')) out.ecosystem_positioning.business_cycle_stage = body;
            else if (l.startsWith('complementors')) out.ecosystem_positioning.complementors_and_partners.push(body);
            else if (l.startsWith('substitutes')) out.ecosystem_positioning.substitutes_and_alternatives.push(body);
            else if (l.startsWith('platform')) out.ecosystem_positioning.platform_and_ecosystem_dynamics = body;
            else if (l.startsWith('white-space')) out.ecosystem_positioning.white_space_opportunities.push(body);
            else if (l.startsWith('business model')) out.ecosystem_positioning.business_model_implications = body;
        });

        const comp = kf.competitive_and_alternatives_analysis || [];
        comp.forEach(item => {
            const { label, body } = splitLabelBody(item);
            if (!label) return;
            const l = label.toLowerCase();
            if (l.startsWith('direct competitors - academic')) out.competitive_landscape.academic_competitors.push(body);
            else if (l.startsWith('direct competitors - industry')) out.competitive_landscape.industry_competitors.push(body);
            else if (l.startsWith('indirect competitors')) out.competitive_landscape.indirect_competitors.push(body);
            else if (l.startsWith('positioning gaps')) out.competitive_landscape.positioning_gaps_and_exploitable_weaknesses.push(body);
            else if (l.startsWith('defensibility')) out.competitive_landscape.defensibility_signals.push(body);
            else if (l.startsWith('competitive response')) out.competitive_landscape.competitive_response_risks.push(body);
            else if (l.startsWith('go-to-market')) out.competitive_landscape.go_to_market_comparison = body;
        });

        const inv = kf.investor_and_funding_framing || [];
        inv.forEach(item => {
            const { label, body } = splitLabelBody(item);
            if (!label) return;
            const l = label.toLowerCase();
            if (/promotion-ready language for pitches/i.test(label)) {
                out.promotion_ready_messaging.for_pitches = body;
            } else if (/promotion-ready language for grant/i.test(label)) {
                out.promotion_ready_messaging.for_grant_applications = body;
            } else if (l.startsWith('why now')) out.investor_and_funding_framing.why_now.push(body);
            else if (l.startsWith('key value drivers')) out.investor_and_funding_framing.key_value_drivers.push(body);
            else if (l.startsWith('risks from investor')) out.investor_and_funding_framing.risks_from_investor_perspective.push(body);
            else if (l.startsWith('comparable transactions')) out.investor_and_funding_framing.comparable_transactions.push(body);
            else if (l.startsWith('investor profiles')) out.investor_and_funding_framing.investor_profiles_and_check_sizes.push(body);
            else if (l.startsWith('likely investor')) out.investor_and_funding_framing.likely_investor_questions.push(body);
        });

        out.recommendations = (data.implications_and_actionable_recommendations || []).map(parseRecommendationPhase_legacy);

        const rcc = data.risks_caveats_and_contrarian_views || [];
        rcc.forEach(text => {
            const parsed = parseRiskItem_legacy(text);
            if (parsed.type === 'risk') {
                out.risks.push({ title: parsed.title, severity: parsed.severity, description: parsed.description });
            } else if (parsed.type === 'contrarian') {
                const fullText = parsed.view;
                let view = fullText, implication = '', counter_argument = '';
                const implMatch = fullText.match(/Implication:\s*([\s\S]*?)(?=Counter-argument:|$)/i);
                const counterMatch = fullText.match(/Counter-argument:\s*([\s\S]*)$/i);
                if (implMatch) {
                    implication = implMatch[1].trim();
                    view = fullText.substring(0, implMatch.index).trim();
                }
                if (counterMatch) counter_argument = counterMatch[1].trim();
                out.contrarian_views.push({
                    title: parsed.title,
                    view, implication, counter_argument
                });
            } else if (parsed.type === 'warning') {
                out.data_staleness_warning = parsed.body;
            }
        });

        out.sources = data.sources || [];
    }

    return out;
}

// =============================================
// Build normalized data
// =============================================

const N = normalize(marketData);

// =============================================
// Extract hero stats from normalized data
// =============================================

function extractFirst(regex, fallback) {
    const allText = [
        ...N.executive_summary,
        N.market_sizing.tam, N.market_sizing.sam, N.market_sizing.som
    ].filter(Boolean).join(' ');
    const m = allText.match(regex);
    return m ? (m[1] || m[0]) : fallback;
}

const tamValue = extractFirst(/TAM[^$]*\$([\d.,\-]+\s*[BMK])/i, '40-50B');
const samValue = extractFirst(/SAM[^$]*\$([\d.,\-]+\s*[BMK])/i, '3-5B');
const somValue = extractFirst(/SOM[^$]*\$([\d.,\-]+\s*[BMK])/i, '50-150M');
// --- CAGR extraction with year range ---
function extractCAGRWithYears() {
    const allText = [
        ...N.executive_summary,
        N.market_sizing.tam, N.market_sizing.sam, N.market_sizing.som
    ].filter(Boolean).join(' ');
    // Match first CAGR (single value or range like "8.6-12.1%")
    const cagrM = allText.match(/CAGR[^%]*?(\d+(?:\.\d+)?(?:\s*[-–]\s*\d+(?:\.\d+)?)?\s*%)/i);
    const cagr = cagrM ? cagrM[1].trim() : 'N/A';
    const idx = cagrM ? cagrM.index : -1;
    let yearStr = '';
    if (idx >= 0) {
        // Search wider context (up to 500 chars before, 200 after) for year pairs
        const ctx = allText.substring(Math.max(0, idx - 500), Math.min(allText.length, idx + 200));
        // Pattern 1: "in 2024 ... by 2033"
        const yr = ctx.match(/in\s+(\d{4})[^.]{0,200}?by\s+(\d{4})/i)
            // Pattern 2: "2024 to 2033", "2024–2033", "2024 - 2033"
            || ctx.match(/(\d{4})\s*(?:to|and|through|thru|[-–—~])\s*(?:by\s+)?(\d{4})/i)
            // Pattern 3: "(2024) ... (2034)"
            || ctx.match(/\((\d{4})\)[^(]{1,200}?\((\d{4})\)/)
            // Pattern 4: "2024" then later "2033" within a short span (last resort)
            || (function() {
                const years = [...ctx.matchAll(/\b((?:19|20)\d{2})\b/g)].map(m => parseInt(m[1]));
                // Find two distinct years where the second is larger
                for (let i = 0; i < years.length; i++) {
                    for (let j = i + 1; j < Math.min(i + 6, years.length); j++) {
                        if (years[j] > years[i]) return [null, String(years[i]), String(years[j])];
                    }
                }
                return null;
            })();
        if (yr && yr[1] && yr[2]) yearStr = `${yr[1]}–${yr[2]}`;
    }
    return { value: cagr, yearStr };
}
