// Merge flat [{label, body}, {label, body}, ...] into [{label, bodies: [body1, body2, ...]}]
// so items with the same label render as a single card with bullet points.
function mergeByLabel(items) {
    const merged = [];
    const indexByKey = {};
    items.forEach(item => {
        const key = item.label || '(unlabeled)';
        if (indexByKey[key] === undefined) {
            indexByKey[key] = merged.length;
            merged.push({ label: item.label, bodies: [item.body] });
        } else {
            merged[indexByKey[key]].bodies.push(item.body);
        }
    });
    return merged;
}

// --- v4 CHANGE: titledCard now uses formatBody() for body text ---
function titledCard(item, accentColor) {
    const c = COLOR[accentColor] || COLOR.blue;
    const bodies = item.bodies || (item.body ? [item.body] : []);
    const isMulti = bodies.length > 1;

    const bodyHTML = isMulti
        ? `<ul class="space-y-2">
              ${bodies.map(b => `
                <li class="flex gap-2 text-slate-700 text-[15px] leading-7">
                    <span class="flex-shrink-0 mt-1.5 w-1.5 h-1.5 ${c.bg500} rounded-full"></span>
                    <span class="flex-1">${formatBody(b)}</span>
                </li>
              `).join('')}
           </ul>`
        : `<div class="text-slate-700 text-[15px] leading-7">${formatBody(bodies[0] || '')}</div>`;

    if (item.label) {
        return `
            <div class="bg-white rounded-2xl p-5 border ${c.border200} hover:${c.border400} hover:shadow-md transition-all">
                <div class="flex items-center justify-between mb-2">
                    <div class="font-display font-semibold ${c.text900} text-xs uppercase tracking-wider">${formatBold(item.label)}</div>
                    ${isMulti ? `<span class="text-[10px] font-bold ${c.text700} ${c.bg100} px-1.5 py-0.5 rounded-full">${bodies.length}</span>` : ''}
                </div>
                ${bodyHTML}
            </div>
        `;
    }
    return `
        <div class="bg-white rounded-2xl p-5 border border-slate-200 hover:shadow-md transition-all">
            ${bodyHTML}
        </div>
    `;
}

function sectionHeader(id, icon, iconColor, title, subtitle) {
