if (!fs.existsSync(dir)) {
    fs.mkdirSync(dir, { recursive: true });
}

fs.writeFileSync(filePath, html, 'utf8');

console.log(`✅ Market Research Report (v4 — inline sources) saved to: ${filePath}`);
console.log(`   Format detected: ${N.format}`);
console.log(`   Hero stats: TAM=$${tamValue} | SAM=$${samValue} | CAGR=${cagrInfo.value} (${cagrInfo.yearStr})`);
console.log(`   Sections: ${N.executive_summary.length} summary paras, ${N.recommendations.length} recommendations, ${N.risks.length} risks, ${N.contrarian_views.length} contrarian views`);
