console.log(`   Sources: ${N.sources.length} items (rendered inline)`);
console.log(`   v4 CHANGE: All source links rendered inline in body text — no separate Sources section`);

return [{ json: { file_path: filePath, status: "success", format: N.format } }];

// ── Node: Build submission_files_info.json Binary ─────────────────────
// Input: N items (each representing a file from PI submission)
// Output: 1 item with binary.data = structured JSON + preserved metadata

const allItems = $input.all();
const first = allItems[0]; // Assume shared project metadata on first item

// Extract filenames and enhanced file metadata
const filesInfo = allItems.map((item, index) => ({
  original_file_name: item.json.file_name || item.binary?.data?.fileName || 'unknown',
}));

const info = {
  file_count: filesInfo.length,
  files: filesInfo,  // Detailed array of extracted filenames + metadata
};

const jsonStr = JSON.stringify(info, null, 2);

