/**
 * n8n Code Node — Score Calculator & Data Merger
 * 
 * POSITION: Place this BEFORE the HTML Report Generator node.
 * 
 * INPUT:  3 items — one per agent, each shaped { json: { output: { agent: "...", ... } } }
 *   items[0] → Regulatory & Certification Strategy Agent
 *   items[1] → Business Evaluation Agent  (CRL, BRL, MRL)
 *   items[2] → Tech Readiness Evaluation Agent (TRL, IPRL, TMRL, FRL)
 * 
 * OUTPUT: 1 item — merged agent data + pre-calculated scoring results
 *   { json: { project_id, tech_field, agents: { regulatory, business, tech }, scoring: { ... } } }
 * 
 * The downstream HTML Report Generator node reads from the `scoring` object
 * and no longer needs to reference $('Business Logic Variables') or perform
 * any calculations itself.
 * 
 * Paste this entire code directly into an n8n "Code" node.
 */

// ============================================
// 1. MERGE AGENT OUTPUTS
// ============================================
function findAgentOutput(items, keyword) {
    const match = items.find(i => new RegExp(keyword, 'i').test(i.json.output?.agent || ''));
    return match ? match.json.output : {};
}

const regData  = findAgentOutput(items, 'Regulatory');
const bizData  = findAgentOutput(items, 'Business');
const techData = findAgentOutput(items, 'Tech');

const formNode  = $('Parse Form & Normalize Binary').first().json;
const projectId = formNode.project_title || '';
const techField = formNode.category   || 'Technology';

// ============================================
// 2. EXTRACT DIMENSION SCORES
// ============================================
const crl  = bizData.CRL?.score  ?? 2;
const brl  = bizData.BRL?.score  ?? 2;
const mrl  = bizData.MRL?.score  ?? 2;
const trl  = techData.TRL?.score  ?? 5;
const iprl = techData.IPRL?.score ?? 5;
const tmrl = techData.TMRL?.score ?? 3;
const frl  = techData.FRL?.score  ?? 1;

// ============================================
// 3. READ WEIGHTS & THRESHOLDS (no defaults)
// ============================================
const blv = $('Business Logic Variables').first().json;

const wCRL  = Number(blv.KTH_CRL_WEIGHT);
const wTRL  = Number(blv.KTH_TRL_WEIGHT);
const wBRL  = Number(blv.KTH_BRL_WEIGHT);
const wIPRL = Number(blv.KTH_IPRL_WEIGHT);
const wTMRL = Number(blv.KTH_TMRL_WEIGHT);
const wFRL  = Number(blv.KTH_FRL_WEIGHT);

const trNoPen  = Number(blv.TRANSLATION_RISK_NO_PENALTY_THRESHOLD);
const trMaxPen = Number(blv.TRANSLATION_RISK_MAX_PENALTY_THRESHOLD);
const mdNoPen  = Number(blv.MATURITY_DELTA_NO_PENALTY_THRESHOLD);
const mdMaxPen = Number(blv.MATURITY_DELTA_MAX_PENALTY_THRESHOLD);

// Decision Matrix thresholds
const COMMERCIAL_KTH_THRESHOLD  = Number(blv.COMMERCIAL_KTH_THRESHOLD);
const COMMERCIAL_TR_THRESHOLD   = Number(blv.COMMERCIAL_TR_THRESHOLD);
const COMMERCIAL_MD_THRESHOLD   = Number(blv.COMMERCIAL_MD_THRESHOLD);
const COMMERCIAL_TMRL_THRESHOLD = Number(blv.COMMERCIAL_TMRL_THRESHOLD);
const COMMERCIAL_IPRL_THRESHOLD = Number(blv.COMMERCIAL_IPRL_THRESHOLD);
const HOLD_TR_THRESHOLD         = Number(blv.HOLD_TR_THRESHOLD);
const HOLD_MD_THRESHOLD          = Number(blv.HOLD_MD_THRESHOLD);

// Penalty Multipliers
const TR_PENALTY_1 = Number(blv.TR_PENALTY_1);
const TR_PENALTY_2 = Number(blv.TR_PENALTY_2);
const MD_PENALTY_1 = Number(blv.MD_PENALTY_1);
const MD_PENALTY_2 = Number(blv.MD_PENALTY_2);

// ============================================
// 4. CALCULATE WEIGHTED SUM
// ============================================
// Formula: Weighted Sum = Σ(wᵢ × Lᵢ) across 6 KTH dimensions
const weightedSum = crl * wCRL + trl * wTRL + brl * wBRL + iprl * wIPRL + tmrl * wTMRL + frl * wFRL;
const maturityDelta = Math.abs(trl - mrl);
let rhoValue = 0;
if (mrl > 0) {rhoValue = ((trl / mrl) * Math.exp(maturityDelta - 2))}

// ============================================
// 5. PENALTY SYSTEM (Tables 4.2 & 4.3)
// ============================================
// Step-function lookups — only the strongest (lowest) multiplier is applied.

// Table 4.2 — Translation Risk (ρ) Penalty
let trMultiplier = 1.00;
if (rhoValue >= trMaxPen)      { trMultiplier = TR_PENALTY_2; }
else if (rhoValue >= trNoPen)  { trMultiplier = TR_PENALTY_1; }

// Table 4.3 — Maturity Delta Penalty
let mdMultiplier = 1.00;
if (maturityDelta > mdMaxPen)       { mdMultiplier = MD_PENALTY_2; }
else if (maturityDelta > mdNoPen)   { mdMultiplier = MD_PENALTY_1; }

const penaltyMultiplier = Math.min(trMultiplier, mdMultiplier);
const penalizedWeightedSum = weightedSum * penaltyMultiplier;

// ============================================
// 6. TRANSLATION RISK LEVEL
// ============================================
let riskLevel, riskColor;
if (maturityDelta >= trMaxPen) {
    riskLevel = "HIGH";
    riskColor = "bg-red-100 text-red-700";
} else if (maturityDelta <= trNoPen) {
    riskLevel = "LOW";
    riskColor = "bg-emerald-100 text-emerald-700";
} else {
    riskLevel = "MODERATE";
    riskColor = "bg-orange-100 text-orange-700";
}

// ============================================
// 7. RECOMMENDATION (Table 4.4 Decision Matrix)
// ============================================
// Rules driven entirely by Business Logic Variables thresholds.
// Text is generated dynamically from the rule that matched,
// referencing actual values and thresholds.
let recLabel, recColor, recReason;

if (penalizedWeightedSum < HOLD_TR_THRESHOLD) {
    recLabel = "STOP / ARCHIVE";
    recColor = "from-red-600 to-red-800";
    recReason = `Penalized Weighted Sum ${penalizedWeightedSum.toFixed(2)} < ${HOLD_TR_THRESHOLD}. The project does not meet the minimum maturity threshold for continued investment.`;
} else if (maturityDelta > HOLD_TR_THRESHOLD || maturityDelta > HOLD_MD_THRESHOLD) {
    recLabel = "HOLD / PIVOT";
    recColor = "from-amber-500 to-orange-500";
    const triggeredHolds = [];
    if (maturityDelta > HOLD_TR_THRESHOLD) triggeredHolds.push(`\u0394 ${maturityDelta.toFixed(1)} > ${HOLD_TR_THRESHOLD} (TR hold)`);
    if (maturityDelta > HOLD_MD_THRESHOLD) triggeredHolds.push(`\u0394 ${maturityDelta.toFixed(1)} > ${HOLD_MD_THRESHOLD} (MD hold)`);
    recReason = `Maturity Delta triggers Hold thresholds: ${triggeredHolds.join(" and ")}. Technology-market alignment requires a strategic pivot or restructuring.`;
} else if (penalizedWeightedSum >= COMMERCIAL_KTH_THRESHOLD
           && maturityDelta <= COMMERCIAL_TR_THRESHOLD
           && maturityDelta <= COMMERCIAL_MD_THRESHOLD
           && tmrl >= COMMERCIAL_TMRL_THRESHOLD
           && iprl >= COMMERCIAL_IPRL_THRESHOLD) {
    recLabel = "ADVANCE TO COMMERCIALIZATION";
    recColor = "from-emerald-500 to-teal-600";
    recReason = `All criteria met: Penalized WS ${penalizedWeightedSum.toFixed(2)} \u2265 ${COMMERCIAL_KTH_THRESHOLD}, \u0394 ${maturityDelta.toFixed(1)} \u2264 ${COMMERCIAL_MD_THRESHOLD} (MD), \u0394 ${maturityDelta.toFixed(1)} \u2264 ${COMMERCIAL_TR_THRESHOLD} (TR), TMRL ${tmrl} \u2265 ${COMMERCIAL_TMRL_THRESHOLD}, IPRL ${iprl} \u2265 ${COMMERCIAL_IPRL_THRESHOLD}. The project is ready to advance to commercialization.`;
} else {
    recLabel = "ACCELERATE / SUPPORT";
    recColor = "from-yellow-500 to-amber-500";
    const unmet = [];
    if (penalizedWeightedSum < COMMERCIAL_KTH_THRESHOLD) unmet.push(`WS ${penalizedWeightedSum.toFixed(2)} < ${COMMERCIAL_KTH_THRESHOLD}`);
    if (maturityDelta > COMMERCIAL_MD_THRESHOLD) unmet.push(`\u0394 ${maturityDelta.toFixed(1)} > ${COMMERCIAL_MD_THRESHOLD}`);
    if (maturityDelta > COMMERCIAL_TR_THRESHOLD) unmet.push(`\u0394 ${maturityDelta.toFixed(1)} > ${COMMERCIAL_TR_THRESHOLD}`);
    if (tmrl < COMMERCIAL_TMRL_THRESHOLD) unmet.push(`TMRL ${tmrl} < ${COMMERCIAL_TMRL_THRESHOLD}`);
    if (iprl < COMMERCIAL_IPRL_THRESHOLD) unmet.push(`IPRL ${iprl} < ${COMMERCIAL_IPRL_THRESHOLD}`);
    recReason = `Penalized WS ${penalizedWeightedSum.toFixed(2)} \u2265 4.0, Hold thresholds not triggered. Project shows promise${unmet.length > 0 ? `. Gaps: ${unmet.join(", ")}` : ''}. Targeted support recommended.`;
}

// ============================================
// 8. OUTPUT MERGED + CALCULATED DATA
// ============================================
return [{
    json: {
        project_id: projectId,
        tech_field: techField,
        agents: {
            regulatory: regData,
            business:   bizData,
            tech:       techData
        },
        scoring: {
            weights: { CRL: wCRL, TRL: wTRL, BRL: wBRL, IPRL: wIPRL, TMRL: wTMRL, FRL: wFRL },
            dimension_scores: { CRL: crl, TRL: trl, BRL: brl, IPRL: iprl, TMRL: tmrl, FRL: frl },
            mrl: mrl,
            weighted_sum: weightedSum,
            maturity_delta: maturityDelta,
            rhoValue: rhoValue,
            penalties: {
                tr_multiplier: trMultiplier,
                md_multiplier: mdMultiplier,
                penalty_multiplier: penaltyMultiplier,
                penalized_weighted_sum: penalizedWeightedSum,
                tr_thresholds: { no_penalty: trNoPen, max_penalty: trMaxPen },
                md_thresholds: { no_penalty: mdNoPen, max_penalty: mdMaxPen }
            },
            thresholds: {
                commercial: {
                    kth: COMMERCIAL_KTH_THRESHOLD,
                    tr: COMMERCIAL_TR_THRESHOLD,
                    md: COMMERCIAL_MD_THRESHOLD,
                    tmrl: COMMERCIAL_TMRL_THRESHOLD,
                    iprl: COMMERCIAL_IPRL_THRESHOLD
                },
                hold: {
                    tr: HOLD_TR_THRESHOLD,
                    md: HOLD_MD_THRESHOLD
                }
            },
            translation_risk: { level: riskLevel, color: riskColor },
            recommendation: { label: recLabel, color: recColor, reason: recReason }
        }
    }
}];

// n8n Code Node - JavaScript
// Purpose: Extract patent numbers and return them as ONE clean array
// Output: Single item containing { patentNumbers: [...] }

const rawInput = $input.first().json;

let dataArray = [];

// Handle different input structures safely
if (Array.isArray(rawInput)) {
  dataArray = rawInput;
} else if (Array.isArray($input.all())) {
  dataArray = $input.all().map(item => item.json);
}

// Helper function to detect real patent numbers
const isPatentNumber = (value) => {
  if (typeof value !== 'string') return false;
  const v = value.trim();
  return /^[A-Z]{2,4}\d{4,}/.test(v);
};

// Extract and clean patent numbers
// NOTE: `row` can be a string OR an array of strings — normalize with flatMap
const patentNumbers = dataArray
  .filter(item => item && typeof item === 'object' && 'row' in item)
  .flatMap(item => {
    const row = item['row'];
    if (Array.isArray(row)) return row;          // ← handle array case
    if (typeof row === 'string') return [row];   // ← handle string case
    return [];
  })
  .filter(val => {
    if (!val || typeof val !== 'string') return false;
    const trimmed = val.trim();
    return trimmed.length > 5 &&
           trimmed !== 'Patent Number' &&
           isPatentNumber(trimmed);
  })
  .map(val => val.trim().replace(/\s/g, ''));

// Return as a single item with all patent numbers inside one array
return [{
  json: {
    patentNumbers: patentNumbers
  }
}];

