const basepath = $('Parse Form & Normalize Binary').first().json.base_path;
const filePath = `${basepath}/00_Admin/technology_summarization.txt`;

const description = $input.first().json.output.description_summary

// Write file
const fs = require('fs');
const path = require('path');

const dir = path.dirname(filePath);
if (!fs.existsSync(dir)) {
    fs.mkdirSync(dir, { recursive: true });
}

fs.writeFileSync(filePath, description, 'utf8');

console.log(`✅ Technology Description saved to: ${filePath}`);

return [{ json: { file_path: filePath, status: "success" } }];

// Merge all incoming items into a single item.
// Strategy:
//   - Plain objects are deep-merged recursively (no key is lost).
//   - Arrays are concatenated.
//   - Primitives (or type mismatches): later item wins.
// This handles the case where Items 2 and 3 both have a top-level
// `output` key — their inner sub-keys don't overlap, so the merged
// `output` object contains all 10 sub-keys from both items.

const items = $input.all();

function isPlainObject(v) {
  return v !== null && typeof v === 'object' && !Array.isArray(v);
}

function deepMerge(target, source) {
  if (isPlainObject(target) && isPlainObject(source)) {
    const result = { ...target };
    for (const key of Object.keys(source)) {
      result[key] = key in result ? deepMerge(result[key], source[key]) : source[key];
    }
    return result;
  }
  if (Array.isArray(target) && Array.isArray(source)) {
    return [...target, ...source];
  }
  // Primitives or mixed types — later item wins
  return source;
}

const merged = {};
for (const item of items) {
  const json = item.json || {};
  for (const key of Object.keys(json)) {
    if (key === 'output' && key in merged) {
      // Rename the second `output` to avoid collision
      merged.output_market = merged.output;
      merged.output_prior_art = json[key];
      delete merged.output;
    } else if (key in merged) {
      merged[key] = deepMerge(merged[key], json[key]);
    } else {
      merged[key] = json[key];
    }
  }
}

return [{ json: merged }];

// =============================================
// Prior Art Analysis Report Generator
// 
// Receives JSON from the Prior Art Analysis Agent and renders a
// scannable, color-coded HTML report. Visual language matches the
// Market Research and Assessment reports (sticky nav, hero stat cards,
// accent-color theming per section, severity-style badges).
//
// Output path: ${basepath}/03_Assessment/Prior_Arts_Anaylsis_Report.html
// =============================================

const basepath = $('Parse Form & Normalize Binary').first().json.base_path;
const filePath = `${basepath}/03_Assessment/Prior_Arts_Anaylsis_Report.html`;

const today = new Date().toISOString().slice(0, 10);

// =============================================
// Load input data (supports both {output: {...}} and flat {})
// =============================================
const _raw = items[0].json || {};
const data = _raw.output || _raw;

const analysisSummary = data.analysis_summary || '';
const rankedPriorArts = Array.isArray(data.ranked_prior_arts) ? data.ranked_prior_arts : [];
const overallNoveltyAssessment = data.overall_novelty_assessment || '';
const recommendations = Array.isArray(data.recommendations) ? data.recommendations : [];
const confidenceLevel = data.confidence_level || '';

// =============================================
// Helper Functions
// =============================================

function escapeHtml(text) {
    if (!text) return '';
    return String(text)
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;');
}

function formatBold(text) {
    if (!text) return '';
    return escapeHtml(text).replace(/\*\*(.*?)\*\*/g, '<strong class="font-semibold text-slate-900">$1</strong>');
}

// Parse "48%" → 48, 0.72 → 72 (number)
function parseSimilarity(scoreStr) {
    if (typeof scoreStr === 'number') {
        // If it's a decimal fraction (0–1), convert to percentage
        return scoreStr > 0 && scoreStr <= 1 ? Math.round(scoreStr * 100) : Math.round(scoreStr);
    }
    if (!scoreStr) return 0;
    const m = String(scoreStr).match(/(\d+(?:\.\d+)?)/);
    if (!m) return 0;
    const val = parseFloat(m[1]);
    // If already has "%" suffix, return as-is; if decimal fraction ≤1, multiply by 100
    return String(scoreStr).includes('%') ? val : (val > 0 && val <= 1 ? Math.round(val * 100) : Math.round(val));
}

// Color theme based on similarity score
function similarityTheme(score) {
    if (score >= 50) return {
        label: 'HIGH OVERLAP',
        color: 'red',
        badge: 'bg-red-100 text-red-700 border-red-200',
        dot: 'bg-red-500',
        bar: 'bg-red-500',
        ring: 'border-red-200'
    };
    if (score >= 30) return {
        label: 'MODERATE OVERLAP',
        color: 'amber',
        badge: 'bg-amber-100 text-amber-700 border-amber-200',
        dot: 'bg-amber-500',
        bar: 'bg-amber-500',
        ring: 'border-amber-200'
    };
    return {
        label: 'LOW OVERLAP',
        color: 'emerald',
        badge: 'bg-emerald-100 text-emerald-700 border-emerald-200',
        dot: 'bg-emerald-500',
        bar: 'bg-emerald-500',
        ring: 'border-emerald-200'
    };
}

// Color theming — pre-built class strings so Tailwind CDN picks them up
const COLOR = {
    blue:    { bg50:'bg-blue-50',    bg100:'bg-blue-100',    bg500:'bg-blue-500',    bg600:'bg-blue-600',    text600:'text-blue-600',    text700:'text-blue-700',    text900:'text-blue-900',    border200:'border-blue-200',    border400:'border-blue-400' },
    emerald: { bg50:'bg-emerald-50', bg100:'bg-emerald-100', bg500:'bg-emerald-500', bg600:'bg-emerald-600', text600:'text-emerald-600', text700:'text-emerald-700', text900:'text-emerald-900', border200:'border-emerald-200', border400:'border-emerald-400' },
    amber:   { bg50:'bg-amber-50',   bg100:'bg-amber-100',   bg500:'bg-amber-500',   bg600:'bg-amber-600',   text600:'text-amber-600',   text700:'text-amber-700',   text900:'text-amber-900',   border200:'border-amber-200',   border400:'border-amber-400' },
    violet:  { bg50:'bg-violet-50',  bg100:'bg-violet-100',  bg500:'bg-violet-500',  bg600:'bg-violet-600',  text600:'text-violet-600',  text700:'text-violet-700',  text900:'text-violet-900',  border200:'border-violet-200',  border400:'border-violet-400' },
    rose:    { bg50:'bg-rose-50',    bg100:'bg-rose-100',    bg500:'bg-rose-500',    bg600:'bg-rose-600',    text600:'text-rose-600',    text700:'text-rose-700',    text900:'text-rose-900',    border200:'border-rose-200',    border400:'border-rose-400' },
    red:     { bg50:'bg-red-50',     bg100:'bg-red-100',     bg500:'bg-red-500',     bg600:'bg-red-600',     text600:'text-red-600',     text700:'text-red-700',     text900:'text-red-900',     border200:'border-red-200',     border400:'border-red-400' },
    slate:   { bg50:'bg-slate-50',   bg100:'bg-slate-100',   bg500:'bg-slate-500',   bg600:'bg-slate-600',   text600:'text-slate-600',   text700:'text-slate-700',   text900:'text-slate-900',   border200:'border-slate-200',   border400:'border-slate-400' },
    teal:    { bg50:'bg-teal-50',    bg100:'bg-teal-100',    bg500:'bg-teal-500',    bg600:'bg-teal-600',    text600:'text-teal-600',    text700:'text-teal-700',    text900:'text-teal-900',    border200:'border-teal-200',    border400:'border-teal-400' },
    indigo:  { bg50:'bg-indigo-50',  bg100:'bg-indigo-100',  bg500:'bg-indigo-500',  bg600:'bg-indigo-600',  text600:'text-indigo-600',  text700:'text-indigo-700',  text900:'text-indigo-900',  border200:'border-indigo-200',  border400:'border-indigo-400' },
};

// =============================================
// Computed stats for hero
// =============================================
const totalPriorArts = rankedPriorArts.length;
const similarityScores = rankedPriorArts.map(p => parseSimilarity(p.similarity_score));
const avgSimilarity = similarityScores.length > 0
    ? Math.round(similarityScores.reduce((a, b) => a + b, 0) / similarityScores.length)
    : 0;
const maxSimilarity = similarityScores.length > 0 ? Math.max(...similarityScores) : 0;

// Overall novelty rating heuristic — based on max similarity
let noveltyRating = { label: 'STRONG NOVELTY', color: 'emerald', pct: 85 };
if (maxSimilarity >= 50) {
    noveltyRating = { label: 'MODERATE NOVELTY', color: 'amber', pct: 60 };
} else if (maxSimilarity >= 30) {
    noveltyRating = { label: 'GOOD NOVELTY', color: 'teal', pct: 75 };
}

// Patent number → Google Patents URL for clickable links
function patentUrl(patentNumber) {
    if (!patentNumber) return null;
    const cleaned = String(patentNumber).trim();
    // Google Patents accepts the patent number directly in the URL
    return `https://patents.google.com/patent/${encodeURIComponent(cleaned)}`;
}

function patentLink(patentNumber) {
    if (!patentNumber) return '';
    const url = patentUrl(patentNumber);
    return `<a href="${url}" target="_blank" class="font-mono text-blue-600 hover:underline font-medium">${escapeHtml(patentNumber)}</a>`;
}

// =============================================
// Hero Stats
// =============================================
const heroStats = [
    { label: 'Prior Arts Analyzed',  value: String(totalPriorArts),                                sub: 'Patents compared',                icon: 'fa-layer-group',      color: 'blue'    },
    { label: 'Highest Similarity',   value: `${maxSimilarity}%`,                                   sub: 'Most overlapping patent',         icon: 'fa-arrow-trend-up',   color: 'amber'   },
    { label: 'Average Similarity',   value: `${avgSimilarity}%`,                                   sub: 'Across all analyzed patents',     icon: 'fa-chart-simple',     color: 'slate'   },
    { label: 'Novelty Assessment',   value: noveltyRating.label,                                   sub: 'Based on max overlap',            icon: 'fa-shield-halved',    color: noveltyRating.color }
];

// =============================================
// Generate HTML
// =============================================

function sectionHeader(id, icon, iconColor, title, subtitle) {
    const c = COLOR[iconColor] || COLOR.blue;
    return `
        <div id="${id}" class="flex items-center gap-x-4 mb-6 scroll-mt-24">
            <div class="w-12 h-12 ${c.bg100} rounded-2xl flex items-center justify-center flex-shrink-0">
                <i class="fa-solid ${icon} ${c.text700} text-xl"></i>
            </div>
            <div>
                <h2 class="text-2xl font-display font-semibold text-slate-900 tracking-tight">${title}</h2>
                ${subtitle ? `<p class="text-slate-500 text-sm mt-0.5">${subtitle}</p>` : ''}
            </div>
        </div>
    `;
}

// Build one big prior-art card
function priorArtCard(pa) {
    const rank = String(pa.rank || '?');
    const patentNumber = pa.patent_number || 'Unknown';
    const similarity = parseSimilarity(pa.similarity_score);
    const theme = similarityTheme(similarity);
    const c = COLOR[theme.color];

    const keyInnovations = Array.isArray(pa.key_innovation_points) ? pa.key_innovation_points : [];
    const keyRefs = Array.isArray(pa.key_references) ? pa.key_references : [];

    return `
        <div class="bg-white rounded-3xl border-2 ${c.border200} overflow-hidden shadow-sm hover:shadow-md transition-shadow scroll-mt-24" id="prior-art-${rank}">
            <!-- Card header: rank badge + patent number + similarity score -->
            <div class="${c.bg50} px-6 py-5 border-b ${c.border200} flex flex-col md:flex-row md:items-center md:justify-between gap-y-3">
                <div class="flex items-center gap-x-4">
                    <div class="w-12 h-12 ${c.bg500} rounded-2xl flex items-center justify-center text-white font-display font-bold text-xl shadow-inner flex-shrink-0">
                        ${escapeHtml(rank)}
                    </div>
                    <div>
                        <div class="text-[10px] font-bold uppercase tracking-widest ${c.text700}">Rank ${escapeHtml(rank)} • Closest prior art ${rank === '1' ? '' : 'match'}</div>
                        <div class="font-display text-xl font-semibold text-slate-900 mt-0.5">${patentLink(patentNumber)}</div>
                    </div>
                </div>
                <div class="flex items-center gap-x-3">
                    <div class="text-right">
                        <div class="text-[10px] font-bold uppercase tracking-widest text-slate-500">Similarity</div>
                        <div class="font-display text-2xl font-bold ${c.text900} leading-none">${similarity}%</div>
                    </div>
                    <span class="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-[10px] font-bold border ${theme.badge}">
                        <span class="w-1.5 h-1.5 rounded-full ${theme.dot}"></span>
                        ${theme.label}
                    </span>
                </div>
            </div>

            <!-- Similarity bar -->
            <div class="h-1 ${c.bg50}">
                <div class="h-full ${theme.bar}" style="width: ${similarity}%"></div>
            </div>

            <!-- Card body -->
            <div class="p-6 space-y-5">

                <!-- Technology & Theory -->
                <div>
                    <div class="flex items-center gap-2 mb-2">
