    else if (num >= 40) confidenceBadge = { label: 'MEDIUM CONFIDENCE', color: 'amber', cls: 'bg-amber-100 text-amber-700 border-amber-200' };
    else confidenceBadge = { label: 'LOW CONFIDENCE', color: 'red', cls: 'bg-red-100 text-red-700 border-red-200' };
}
const confidenceBody = confStr.replace(/^(High|Medium|Low)\s*[-–—:]\s*/i, '').trim() || `${confStr}/100`;

const projectTitle = $('Parse Form & Normalize Binary').first().json.project_title || 'Prior Art Analysis Report';

