function generateAssessmentHTML(data, techCategory, savingPath) {
    const reg = data.agents?.regulatory || {};
    const market = data.agents?.business || {};
    const tech = data.agents?.tech || {};
    const sc = data.scoring || {};

    const projectSummary = reg.project_technology_summary || 
        "This project involves a novel technology with quantified performance improvements and filed intellectual property.";

    // Title: use project_id first, then project_name, then tech_field
    let projectTitle = data.project_id || data.project_name || data.tech_field || 'Technology Assessment Assessment Report';

    // === ALL VALUES FROM PRE-CALCULATED SCORING OBJECT (Node A) ===
    const crl  = sc.dimension_scores?.CRL  ?? 2;
    const trl  = sc.dimension_scores?.TRL  ?? 5;
    const brl  = sc.dimension_scores?.BRL  ?? 2;
    const iprl = sc.dimension_scores?.IPRL ?? 5;
    const tmrl = sc.dimension_scores?.TMRL ?? 3;
    const frl  = sc.dimension_scores?.FRL  ?? 1;
    const mrl  = sc.mrl ?? 2;

    const wCRL  = sc.weights?.CRL  ?? 0;
    const wTRL  = sc.weights?.TRL  ?? 0;
    const wBRL  = sc.weights?.BRL  ?? 0;
    const wIPRL = sc.weights?.IPRL ?? 0;
    const wTMRL = sc.weights?.TMRL ?? 0;
    const wFRL  = sc.weights?.FRL  ?? 0;

    const weightedSum = sc.weighted_sum ?? 0;
    const kthAverage = weightedSum.toFixed(1);
    const maturityDelta = sc.maturity_delta ?? 0;

    // Translation Risk ρ = (TRL / MRL) × exp(|TRL − MRL| − 2)
    const rhoValueNum = mrl > 0 ? (trl / mrl) * Math.exp(maturityDelta - 2) : NaN;
    const rhoValue = mrl > 0 ? rhoValueNum.toFixed(1) : 'N/A (MRL=0)';

    // Penalty thresholds & multipliers
    const trNoPen  = sc.penalties?.tr_thresholds?.no_penalty  ?? 0;
    const trMaxPen = sc.penalties?.tr_thresholds?.max_penalty ?? 0;
    const mdNoPen  = sc.penalties?.md_thresholds?.no_penalty  ?? 0;
    const mdMaxPen = sc.penalties?.md_thresholds?.max_penalty ?? 0;

    const blv = $('Business Logic Variables').first().json;
    const TR_PENALTY_1 = Number(blv.TR_PENALTY_1);
    const TR_PENALTY_2 = Number(blv.TR_PENALTY_2);
    const MD_PENALTY_1 = Number(blv.MD_PENALTY_1);
    const MD_PENALTY_2 = Number(blv.MD_PENALTY_2);

    const trMultiplier = sc.penalties?.tr_multiplier ?? 1;
    const mdMultiplier = sc.penalties?.md_multiplier ?? 1;
    const penaltyMultiplier = sc.penalties?.penalty_multiplier ?? 1;
    const penalizedWeightedSum = sc.penalties?.penalized_weighted_sum ?? 0;

    function formatPenaltyMultiplier(value) {
        return value.toFixed(2).replace(/0+$/, '').replace(/\.$/, '.0');
    }

    // Decision matrix thresholds
    const COMMERCIAL_KTH_THRESHOLD  = sc.thresholds?.commercial?.kth  ?? 0;
    const COMMERCIAL_TR_THRESHOLD   = sc.thresholds?.commercial?.tr   ?? 0;
    const COMMERCIAL_MD_THRESHOLD   = sc.thresholds?.commercial?.md   ?? 0;
    const COMMERCIAL_TMRL_THRESHOLD = sc.thresholds?.commercial?.tmrl ?? 0;
    const COMMERCIAL_IPRL_THRESHOLD = sc.thresholds?.commercial?.iprl ?? 0;
    const HOLD_TR_THRESHOLD         = sc.thresholds?.hold?.tr  ?? 0;
    const HOLD_MD_THRESHOLD          = sc.thresholds?.hold?.md  ?? 0;

    // Pre-calculated recommendation & risk
    const riskLevel = sc.translation_risk?.level ?? 'MODERATE';
    const riskColor = sc.translation_risk?.color ?? 'bg-orange-100 text-orange-700';
    const recLabel  = sc.recommendation?.label  ?? 'ACCELERATE / SUPPORT';
    const recColor  = sc.recommendation?.color  ?? 'from-yellow-500 to-amber-500';
    const recReason = sc.recommendation?.reason ?? '';

    // === RRL (from regulatory agent data) ===
    const rrlScore = reg.current_rrl_level ?? 1;
    const rrlMax = 5;
    const rrlJustification = reg.rrl_justification || '';
    const rrlRecommendations = reg.rrl_recommendations || [];

    // === JUSTIFICATIONS (from agent data) ===
    const crlJust = market.CRL?.justification || "Market need identified. Limited primary customer validation available.";
    const brlJust = market.BRL?.justification || "Business concept described. Detailed financial modeling and market sizing pending.";
    const trlJust = tech.TRL?.justification || "Technology validated in relevant environment.";
    const iprlJust = tech.IPRL?.justification || "Key intellectual property filed.";
    const tmrlJust = tech.TMRL?.justification || "Core technical team in place. Commercial competencies need strengthening.";
    const frlJust = tech.FRL?.justification || "Funding requirements and roadmap not yet defined.";

    const regulatoryConsiderations = reg.key_regulatory_considerations || [];
    const certs = reg.recommended_certifications || [];
    const gaps = reg.major_gaps_or_risks || [];
    const recs = reg.strategic_recommendations || [];

    const today = new Date().toISOString().slice(0, 10);

    // === RRL COLOR THEMING (1-5 scale) ===
    let rrlBadgeColor = 'bg-red-100 text-red-700';
    let rrlBarColor = 'linear-gradient(90deg, #ef4444, #b91c1c)';
    if (rrlScore >= 4) {
        rrlBadgeColor = 'bg-emerald-100 text-emerald-700';
        rrlBarColor = 'linear-gradient(90deg, #14b8a6, #0f766e)';
    } else if (rrlScore === 3) {
        rrlBadgeColor = 'bg-amber-100 text-amber-700';
        rrlBarColor = 'linear-gradient(90deg, #f59e0b, #d97706)';
    } else if (rrlScore === 2) {
        rrlBadgeColor = 'bg-orange-100 text-orange-700';
        rrlBarColor = 'linear-gradient(90deg, #f97316, #c2410c)';
    }

    let rrlPct = Math.round((rrlScore / rrlMax) * 100);

    // Dynamic regulatory cards
    let regulatoryCardsHTML = '';
    if (regulatoryConsiderations.length > 0) {
        regulatoryCardsHTML = regulatoryConsiderations.map(item => {
            if (typeof item === 'string') {
                return `
                    <div class="border border-slate-200 rounded-2xl p-5">
                        <div class="text-sm text-slate-700 leading-relaxed">${item}</div>
                    </div>
                `;
            } else {
