                                <div class="text-slate-700 leading-relaxed">${item.key_requirements || '—'}</div>
                            </div>
                            ${item.notes ? `<div class="pt-2 border-t border-slate-100 italic text-slate-500"><span class="font-medium not-italic">Notes:</span> ${item.notes}</div>` : ''}
