                `;
            }
        }).join('');
    } else {
        regulatoryCardsHTML = `<div class="col-span-3 text-sm text-slate-500 p-4 bg-slate-50 rounded-2xl">No specific regulatory market considerations provided.</div>`;
    }

    // Dynamic certifications table
    let certsTableHTML = '';
    if (certs.length > 0) {
        certsTableHTML = certs.map(cert => {
            if (typeof cert === 'string') {
                return `
                    <tr>
                        <td class="py-3 px-4 font-semibold">${cert}</td>
