        }).join('');
    } else {
        certsTableHTML = `<tr><td colspan="4" class="py-4 px-4 text-center text-slate-500">No certification recommendations in input data.</td></tr>`;
    }

    const gapsHTML = gaps.length > 0 
        ? gaps.map(g => `<li class="flex gap-x-2"><i class="fa-solid fa-exclamation-triangle text-red-500 mt-1 fa-fw"></i><span>${g}</span></li>`).join('')
        : `<li class="text-slate-500">No major gaps flagged.</li>`;

    const recsHTML = recs.length > 0
