        : `<li class="text-slate-500">No strategic recommendations provided.</li>`;

    // === RRL LADDER (5-level visual) ===
    let rrlLadderHTML = '';
    for (let i = 1; i <= 5; i++) {
        const isCurrent = i === rrlScore;
        const isPassed = i < rrlScore;
        const desc = KTH_RUBRICS.RRL.levels[i];
        const stateClass = isCurrent
            ? 'border-teal-500 bg-teal-50 ring-2 ring-teal-300'
            : isPassed
                ? 'border-emerald-200 bg-emerald-50/50'
                : 'border-slate-200 bg-white';
        const badgeClass = isCurrent
            ? 'bg-teal-600 text-white'
            : isPassed
                ? 'bg-emerald-500 text-white'
                : 'bg-slate-200 text-slate-500';
        const marker = isCurrent
            ? '<i class="fa-solid fa-location-pin ml-1 text-teal-600"></i>'
            : isPassed
                ? '<i class="fa-solid fa-check ml-1 text-emerald-600"></i>'
                : '';
        rrlLadderHTML += `
            <div class="flex items-start gap-3 p-3 rounded-2xl border ${stateClass} transition-all">
                <div class="flex-shrink-0 w-9 h-9 rounded-xl ${badgeClass} flex items-center justify-center font-display font-bold text-sm">${i}${marker ? '' : ''}</div>
                <div class="flex-1 min-w-0">
                    <div class="flex items-center gap-2 flex-wrap">
                        <span class="font-semibold text-sm">RRL ${i}</span>
                        ${isCurrent ? '<span class="assessment-pill bg-teal-200 text-teal-800">CURRENT</span>' : ''}
