                </div>
            </div>
        `;
    }

    // === LEVEL COLOR HELPER (1-3=red, 4-6=yellow, 7-9=green) ===
    function getLevelColors(score) {
        if (score >= 7) return {
            border: 'border-emerald-100', bg: 'bg-emerald-50/30',
            badge: 'bg-emerald-600', pill: 'bg-emerald-200 text-emerald-700',
            cardBorder: 'border-emerald-200', cardBg: 'bg-emerald-50/40',
            cardPill: 'bg-emerald-100 text-emerald-700'
        };
        if (score >= 4) return {
            border: 'border-yellow-100', bg: 'bg-yellow-50/30',
            badge: 'bg-yellow-600', pill: 'bg-yellow-200 text-yellow-700',
            cardBorder: 'border-yellow-200', cardBg: 'bg-yellow-50/40',
            cardPill: 'bg-yellow-100 text-yellow-700'
        };
        return {
            border: 'border-red-100', bg: 'bg-red-50/30',
            badge: 'bg-red-600', pill: 'bg-red-200 text-red-700',
            cardBorder: 'border-red-200', cardBg: 'bg-red-50/40',
