    // === KTH DIMENSION RUBRIC CARDS (current level + collapsible full ladder) ===
    function buildDimensionRubricCard(code, currentScore, justification) {
        const rubric = KTH_RUBRICS[code];
        const currentDesc = rubric.levels[currentScore] || '—';
        const colors = getLevelColors(currentScore);
        const colorClass = colors.cardBorder + ' ' + colors.cardBg;
        const pillClass = colors.cardPill;

        // Build the full ladder rows
        let ladderRows = '';
        for (let i = 1; i <= rubric.max; i++) {
            const isCurrent = i === currentScore;
            const rowClass = isCurrent ? 'bg-teal-50 border-l-4 border-teal-500' : 'border-l-4 border-transparent';
            ladderRows += '<div class="' + rowClass + ' px-3 py-2 text-xs"><div class="flex items-start gap-2"><span class="font-bold ' + (isCurrent ? 'text-teal-700' : 'text-slate-500') + ' flex-shrink-0">' + code + ' ' + i + '</span><span class="' + (isCurrent ? 'text-slate-900 font-medium' : 'text-slate-600') + '">' + rubric.levels[i] + '</span></div></div>';
        }

        return '<div class="border ' + colorClass + ' rounded-2xl overflow-hidden">' +
            '<div class="p-4">' +
                '<div class="flex items-center justify-between mb-2">' +
                    '<div class="flex items-center gap-2">' +
                        '<span class="font-display font-semibold text-slate-900">' + code + '</span>' +
                        '<span class="text-xs text-slate-500">' + rubric.label + '</span>' +
                    '</div>' +
                    '<span class="assessment-pill ' + pillClass + '">LEVEL ' + currentScore + ' / ' + rubric.max + '</span>' +
                '</div>' +
                '<div class="text-xs text-slate-600 bg-white/60 rounded-lg p-2 mb-2">' +
                    '<span class="font-semibold text-slate-700">Current level meaning:</span> ' + currentDesc +
                '</div>' +
                (justification ? '<div class="text-xs text-slate-500 italic leading-relaxed">' + justification + '</div>' : '') +
            '</div>' +
            '<details class="border-t border-slate-200/60">' +
                '<summary class="cursor-pointer px-4 py-2 text-xs font-semibold text-teal-700 hover:bg-teal-50 flex items-center gap-2">' +
                    '<i class="fa-solid fa-list-ul"></i>' +
                    'Show full ' + code + ' rubric (' + rubric.max + ' levels)' +
                '</summary>' +
                '<div class="divide-y divide-slate-100 bg-white/40">' +
                    ladderRows +
                '</div>' +
            '</details>' +
        '</div>';
    }

    const rubricCardsHTML = [
        buildDimensionRubricCard('CRL', crl, crlJust),
        buildDimensionRubricCard('TRL', trl, trlJust),
        buildDimensionRubricCard('BRL', brl, brlJust),
        buildDimensionRubricCard('IPRL', iprl, iprlJust),
        buildDimensionRubricCard('TMRL', tmrl, tmrlJust),
        buildDimensionRubricCard('FRL', frl, frlJust),
        buildDimensionRubricCard('MRL', mrl, ''),
    ].join('\n');

    const html = `<!DOCTYPE html>
