/**
 * n8n Code Node v7b — Strategy Planning Agent HTML Report
 *
 * v7 → v7b change:
 *   - CRITICAL FIX: All quantitative/metric data (dimension scores, weighted sums,
 *     penalties, translation risk, evaluation recommendation, MRL, RRL) is now
 *     extracted DIRECTLY from the "Merging All Research Items" node — NOT from
 *     the AI agent's JSON output. This prevents the AI agent from altering numbers.
 *   - The AI agent output (items[0].json) is used ONLY for qualitative/strategic
 *     content: pathway, posture, commercialization strategy, risk stratification,
 *     actions, strengths, gaps, investor framing, reviewer notes, confidence.
 *
 * Data sources:
 *   - $('Merging All Research Items').first().json  → all scores/metrics (ground truth)
 *   - items[0].json                                 → strategy content (AI suggestions)
 *   - $('Parse Form & Normalize Binary')            → basepath, category
 *
 * Output: Saved HTML report to 04_Strategy/
 */

// ============================================
// 1. INPUT — TWO SOURCES
// ============================================
const basepath = $('Parse Form & Normalize Binary').first().json.base_path || '/tmp';
const techCategory = $('Parse Form & Normalize Binary').first().json.category || 'Deep Tech';

const savingPath = basepath.endsWith('/') ? basepath + '04_Strategy' : basepath + '/04_Strategy';

const fs = require('fs');
const path = require('path');

if (!fs.existsSync(savingPath)) {
    fs.mkdirSync(savingPath, { recursive: true });
}

// --- SOURCE A: AI agent's strategy output (qualitative only) ---
const raw = items[0].json;
const data = raw.output || raw;

// --- SOURCE B: Merging All Research Items (quantitative ground truth) ---
const mergeNode = $('Merging All Research Items').first().json;
const scoring = (mergeNode && mergeNode.scoring) || {};
const mergeAgents = (mergeNode && mergeNode.agents) || {};
const regAgent = mergeAgents.regulatory || {};

// ============================================
// 2. EXTRACT EVALUATION METRICS FROM MERGE NODE
// ============================================
const dimScores = scoring.dimension_scores || {};
const ev_trl = dimScores.TRL ?? 0;
const ev_crl = dimScores.CRL ?? 0
const ev_brl = dimScores.BRL ?? 0;
const ev_iprl = dimScores.IPRL ?? 0;
const ev_tmrl = dimScores.TMRL ?? 0;
const ev_frl = dimScores.FRL ?? 0;

const ev_mrl = scoring.mrl ?? null;
const ev_kthSum = scoring.weighted_sum ?? 0;
const ev_delta = scoring.maturity_delta ?? 0;

// Penalty details
const penalties = scoring.penalties || {};
const ev_trMultiplier = penalties.tr_multiplier ?? null;
const ev_mdMultiplier = penalties.md_multiplier ?? null;
const ev_penaltyMultiplier = penalties.penalty_multiplier ?? null;
const ev_penalizedSum = penalties.penalized_weighted_sum ?? ev_kthSum;
const ev_penaltyApplied = ev_penaltyMultiplier !== null && ev_penaltyMultiplier < 1;

// Translation risk
const transRisk = scoring.translation_risk || {};
const ev_trLevel = transRisk.level || 'N/A';

// Evaluation recommendation
const evRec = scoring.recommendation || {};
const evRecLabel = evRec.label || 'N/A';
const evRecReason = evRec.reason || '';

// Regulatory Readiness Level (from regulatory agent in merge node)
const ev_rrl = regAgent.current_rrl_level ?? 0;

// Build penalty details string from ground truth
function buildPenaltyDetailString() {
    const parts = [];
    if (ev_trMultiplier !== null) {
        parts.push('Translation Risk multiplier: ' + ev_trMultiplier);
    }
    if (ev_mdMultiplier !== null) {
        parts.push('Maturity Delta multiplier: ' + ev_mdMultiplier);
    }
    if (ev_penaltyMultiplier !== null && ev_penaltyMultiplier < 1) {
        parts.push('Combined penalty multiplier: ' + ev_penaltyMultiplier);
        parts.push('Weighted sum reduced from ' + ev_kthSum + ' to ' + ev_penalizedSum);
    }
    if (evRecReason) {
        parts.push(evRecReason);
    }
    return parts.join('. ') || '';
}

// ============================================
// 3. HELPERS
// ============================================
const today = new Date().toISOString().slice(0, 10);

function esc(str) {
    if (!str) return '';
    return String(str)
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;');
}

// ============================================
// 4. GENERATOR
// ============================================
function generateReport(data, techCategory, savingPath) {
    const assessmentId = data.assessment_id || 'ASSESSMENT';
    const projectId = data.project_id || '';
    const techField = data.tech_field || techCategory;

    // --- Strategy recommendation (from AI agent) ---
    const sr = data.strategic_recommendation || {};
    const pathway = sr.pathway || 'TBD';
    const posture = sr.strategic_posture || '';
    const endorsement = sr.endorsement_of_evaluation || 'N/A';
    const endorsementJust = sr.endorsement_justification || '';

    // --- Commercialization strategy (from AI agent) ---
    const cs = data.commercialization_strategy || {};
    const valueProp = cs.value_proposition || '';
    const targetMarket = cs.target_market_priority || '';
    const gtmThesis = cs.go_to_market_thesis || '';
    const moatAssessment = cs.competitive_moat_assessment || '';
    const regPathway = cs.regulatory_pathway_summary || '';
    const fundingStrat = cs.funding_strategy || '';

    // --- Risk stratification (from AI agent) ---
    const rs = data.risk_stratification || {};
    const showstoppers = rs.showstoppers || [];
    const materialRisks = rs.material_risks || [];
    const manageableRisks = rs.manageable_risks || [];

    // --- Prioritized actions (from AI agent) ---
    const actions = data.prioritized_actions || [];

    // --- Other fields (from AI agent) ---
    const strengths = data.key_strengths || [];
    const gaps = data.critical_gaps || [];
    const investorFraming = data.investor_framing_highlights || '';
    const confidence = data.confidence_in_assessment || '';
    const reviewerNotes = data.notes_for_human_reviewer || '';

    // --- Visual helpers ---
    const pathwayColors = {
        'Spinout / Venture': 'bg-emerald-100 text-emerald-700 border-emerald-200',
        'Licensing / JDA': 'bg-sky-100 text-sky-700 border-sky-200',
        'Further R&D / Incubation': 'bg-amber-100 text-amber-700 border-amber-200',
        'Archive / Monitor': 'bg-red-100 text-red-700 border-red-200'
    };
    const pathwayClass = pathwayColors[pathway] || 'bg-slate-100 text-slate-700 border-slate-200';

    const endorsementColors = {
        'Fully Endorsed': 'bg-emerald-50 text-emerald-700 border-emerald-200',
        'Endorsed with Nuance': 'bg-sky-50 text-sky-700 border-sky-200',
        'Upgraded': 'bg-emerald-50 text-emerald-700 border-emerald-200',
        'Downgraded': 'bg-orange-50 text-orange-700 border-orange-200'
    };
    const endorsementClass = endorsementColors[endorsement] || 'bg-slate-50 text-slate-600 border-slate-200';

    let confidenceClass = 'bg-slate-100 text-slate-700 border-slate-200';
    const confLower = confidence.toLowerCase();
    if (confLower.includes('high') && !confLower.includes('medium')) confidenceClass = 'bg-emerald-100 text-emerald-700 border-emerald-200';
    else if (confLower.includes('medium')) confidenceClass = 'bg-amber-100 text-amber-700 border-amber-200';
    else if (confLower.includes('low')) confidenceClass = 'bg-red-100 text-red-700 border-red-200';

    const trColors = {
        'LOW': 'bg-emerald-50 text-emerald-700 border-emerald-200',
        'MODERATE': 'bg-amber-50 text-amber-700 border-amber-200',
        'HIGH': 'bg-red-50 text-red-700 border-red-200',
        'VERY HIGH': 'bg-red-100 text-red-800 border-red-300'
    };
    const trClass = trColors[ev_trLevel] || 'bg-slate-50 text-slate-600 border-slate-200';

    // Evaluation recommendation badge color (from merge node ground truth)
    const evRecNorm = (evRecLabel || '').toUpperCase().replace(/[\s\/]+/g, '');
    let evRecClass = 'bg-slate-100 text-slate-700 border-slate-200';
    if (evRecNorm.includes('ADVANCE') && !evRecNorm.includes('STOP')) evRecClass = 'bg-emerald-100 text-emerald-700 border-emerald-200';
    else if (evRecNorm.includes('ACCELERATE') || evRecNorm.includes('SUPPORT')) evRecClass = 'bg-sky-100 text-sky-700 border-sky-200';
    else if (evRecNorm.includes('HOLD') || evRecNorm.includes('PIVOT')) evRecClass = 'bg-orange-100 text-orange-700 border-orange-200';
    else if (evRecNorm.includes('STOP') || evRecNorm.includes('ARCHIVE')) evRecClass = 'bg-red-100 text-red-700 border-red-200';

    // Priority badge colors for actions
    const priorityColors = {
        'Critical': 'bg-red-100 text-red-700 border-red-200',
        'High': 'bg-orange-100 text-orange-700 border-orange-200',
        'Medium': 'bg-sky-100 text-sky-700 border-sky-200'
    };
    function pClass(p) { return priorityColors[p] || 'bg-slate-100 text-slate-600 border-slate-200'; }

    // Timeframe colors
    const tfColors = {
        'Immediate (0–3 months)': 'bg-red-50 text-red-700',
        'Short-term (3–12 months)': 'bg-amber-50 text-amber-700',
        'Medium-term (12–36 months)': 'bg-sky-50 text-sky-700'
    };
    function tfClass(tf) { return tfColors[tf] || 'bg-slate-50 text-slate-600'; }

    // Count actions by timeframe
    const immCount = actions.filter(a => (a.timeframe || '').startsWith('Immediate')).length;
    const shortCount = actions.filter(a => (a.timeframe || '').startsWith('Short')).length;
    const medCount = actions.filter(a => (a.timeframe || '').startsWith('Medium')).length;

    // Build penalty details from ground truth
    const penaltyDetailsStr = buildPenaltyDetailString();

    // Build action table rows
    const actionRows = actions.map((a, i) => `
        <tr class="${i % 2 === 0 ? 'bg-white' : 'bg-slate-50/50'}">
            <td class="px-3 py-2 text-xs font-semibold text-slate-700">${i + 1}</td>
            <td class="px-3 py-2 text-xs text-slate-700 leading-snug">${esc(a.action)}</td>
            <td class="px-3 py-2 text-center">
                <span class="inline-block px-2 py-0.5 rounded text-[11px] font-semibold ${tfClass(a.timeframe)}">${a.timeframe || '—'}</span>
            </td>
            <td class="px-3 py-2 text-center">
                <span class="inline-block px-2 py-0.5 rounded text-[11px] font-semibold border ${pClass(a.priority)}">${a.priority || '—'}</span>
            </td>
            <td class="px-3 py-2 text-center text-[11px] text-slate-600">${esc(a.responsible_party || '—')}</td>
            <td class="px-3 py-2 text-[11px] text-slate-500">${esc(a.strategic_pillar || '—')}</td>
            <td class="px-3 py-2 text-[11px] text-slate-500">${esc(a.dependencies || '—')}</td>
        </tr>
    `).join('');

    // Build risk items
    const buildRiskList = (items, colorClass) => {
        if (!items.length) return '<div class="text-xs text-slate-400 italic">None identified</div>';
        return '<ul class="space-y-1.5 text-xs text-slate-600 leading-snug">' +
            items.map(r => `<li class="flex gap-x-1.5"><span class="${colorClass} shrink-0">\u2022</span><span>${esc(r)}</span></li>`).join('') +
            '</ul>';
    };

    const html = `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Strategy Plan \u2022 ${esc(assessmentId)}</title>
    <script src="https://cdn.tailwindcss.com"></script>
    <link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.5.1/css/all.min.css">
    <script src="https://cdn.jsdelivr.net/npm/chart.js@4.4.1/dist/chart.umd.min.js"></script>
    <style>
        @import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600&family=Space+Grotesk:wght@500;600&display=swap');
        body { font-family: 'Inter', system-ui, sans-serif; background-color: #f8fafc; font-size: 15px; }
        .text-\\[10px\\] { font-size: 12px !important; }
        .text-\\[11px\\] { font-size: 13px !important; }
        .text-xs { font-size: 13px !important; }
        .font-display { font-family: 'Space Grotesk', 'Inter', sans-serif; font-weight: 600; }
        .metric-value { font-variant-numeric: tabular-nums; }
        details > summary { list-style: none; }
        details > summary::-webkit-details-marker { display: none; }
        details[open] > summary .chev { transform: rotate(90deg); }
        .chev { transition: transform 0.15s ease; }
    </style>
</head>
<body class="text-slate-800">
    <div class="max-w-screen-2xl mx-auto px-5 py-5">

        <!-- ==================== HEADER ==================== -->
        <div class="flex items-start justify-between mb-4">
            <div>
                <div class="flex items-center gap-x-2 mb-1 flex-wrap">
                    <div class="font-mono text-[11px] px-2 py-0.5 bg-white border border-slate-200 rounded-lg">${esc(assessmentId)}</div>
                    <div class="px-2 py-0.5 text-[11px] font-semibold border rounded-lg ${pathwayClass}"><i class="fa-solid fa-route mr-1"></i>${esc(pathway)}</div>
                    <div class="px-2 py-0.5 text-[11px] font-semibold border rounded-lg ${evRecClass}"><i class="fa-solid fa-gavel mr-1"></i>Eval: ${esc(evRecLabel)}</div>
                    <div class="px-2 py-0.5 text-[11px] font-semibold border rounded-lg ${trClass}"><i class="fa-solid fa-radio mr-1"></i>TR: ${esc(ev_trLevel)}</div>
                    ${confidence ? `<div class="px-2 py-0.5 text-[11px] font-semibold border rounded-lg ${confidenceClass}"><i class="fa-solid fa-gauge-high mr-1"></i>${esc(confidence)}</div>` : ''}
                </div>
                <h1 class="font-display text-2xl tracking-tight">Commercialization Strategy Plan</h1>
                <p class="text-slate-500 text-xs mt-0.5">${esc(projectId)} \u2022 ${esc(techField)}</p>
            </div>
            <div class="text-right text-[11px] text-slate-400">
                Generated ${today}<br>
                <span class="font-mono">${esc(savingPath)}</span>
            </div>
        </div>

        <!-- ==================== STRATEGIC POSTURE BANNER ==================== -->
        <div class="bg-gradient-to-r from-indigo-50 to-slate-50 border border-indigo-200 rounded-xl p-4 mb-3">
            <div class="flex items-center gap-x-2 mb-2">
                <i class="fa-solid fa-compass text-indigo-500"></i>
                <span class="text-[10px] uppercase tracking-wider text-indigo-600 font-bold">Strategic Posture</span>
                <span class="ml-auto px-2 py-0.5 text-[10px] font-semibold border rounded ${endorsementClass}">${esc(endorsement)}</span>
            </div>
            <div class="text-sm text-slate-800 leading-relaxed font-medium">${esc(posture)}</div>
            ${endorsementJust ? `<div class="text-xs text-slate-600 leading-snug mt-2 border-t border-indigo-100 pt-2"><strong class="text-indigo-700">Endorsement Note:</strong> ${esc(endorsementJust)}</div>` : ''}
        </div>

        <!-- ==================== EVALUATION SUMMARY (FROM MERGE NODE — GROUND TRUTH) ==================== -->
        <details class="bg-white border border-slate-200 rounded-xl mb-3" ${ev_penaltyApplied ? '' : 'open'}>
            <summary class="px-4 py-2.5 cursor-pointer hover:bg-slate-50 flex items-center justify-between">
                <span class="flex items-center gap-x-2">
                    <i class="fa-solid fa-chevron-right chev text-slate-500 text-xs"></i>
                    <span class="font-semibold text-sm">Evaluation Summary <span class="ml-1 text-[10px] text-slate-500 font-normal">(sourced directly from Evaluation Agent \u2014 not AI-interpreted)</span></span>
                </span>
                <span class="text-[10px] text-slate-400">scores + metrics</span>
            </summary>
            <div class="px-4 pb-3 border-t border-slate-100">
                <!-- Metrics Row -->
                <div class="grid grid-cols-2 md:grid-cols-6 gap-2 mt-3 mb-3">
                    <div class="bg-slate-50 border border-slate-200 rounded-lg p-2.5">
                        <div class="text-[10px] uppercase tracking-wider text-slate-500">KTH Weighted</div>
                        <div class="text-xl font-display font-semibold metric-value">${ev_kthSum.toFixed(3)}</div>
                        <div class="text-[10px] text-slate-400">pre-penalty</div>
                    </div>
                    <div class="bg-slate-50 border border-slate-200 rounded-lg p-2.5">
                        <div class="text-[10px] uppercase tracking-wider text-slate-500">Penalized Score</div>
                        <div class="text-xl font-display font-semibold metric-value ${ev_penaltyApplied ? 'text-orange-600' : ''}">${ev_penalizedSum}</div>
                        <div class="text-[10px] text-slate-400">${ev_penaltyApplied ? 'Penalty applied' : 'No penalty'}</div>
                    </div>
                    <div class="bg-slate-50 border border-slate-200 rounded-lg p-2.5">
                        <div class="text-[10px] uppercase tracking-wider text-slate-500">Maturity Delta</div>
                        <div class="text-xl font-display font-semibold metric-value ${ev_delta > 3.5 ? 'text-red-600' : ev_delta > 2 ? 'text-amber-600' : 'text-emerald-600'}">${ev_delta}</div>
                        <div class="text-[10px] text-slate-400">${ev_mrl !== null ? 'TRL ' + ev_trl + ' \u2212 MRL ' + ev_mrl : '|TRL \u2212 MRL|'}</div>
                    </div>
                    <div class="bg-slate-50 border border-slate-200 rounded-lg p-2.5">
                        <div class="text-[10px] uppercase tracking-wider text-slate-500">MRL</div>
                        <div class="text-xl font-display font-semibold metric-value text-indigo-600">${ev_mrl ?? '\u2014'}</div>
                        <div class="text-[10px] text-slate-400">Market Readiness</div>
                    </div>
                    <div class="bg-slate-50 border border-slate-200 rounded-lg p-2.5">
                        <div class="text-[10px] uppercase tracking-wider text-slate-500">RRL</div>
                        <div class="text-xl font-display font-semibold metric-value">${ev_rrl}</div>
                        <div class="text-[10px] text-slate-400">informational</div>
                    </div>
                    <div class="bg-slate-50 border border-slate-200 rounded-lg p-2.5">
                        <div class="text-[10px] uppercase tracking-wider text-slate-500">Trans. Risk</div>
                        <div class="text-sm font-display font-semibold mt-1"><span class="px-2 py-0.5 rounded text-[11px] border ${trClass}">${esc(ev_trLevel)}</span></div>
                        <div class="text-[10px] text-slate-400 mt-1">\u03c1-based</div>
                    </div>
                </div>

                ${ev_penaltyApplied && penaltyDetailsStr ? `
                <div class="bg-orange-50 border border-orange-200 rounded-lg p-2.5 mb-3 flex gap-x-2">
                    <i class="fa-solid fa-triangle-exclamation text-orange-500 mt-0.5 shrink-0"></i>
                    <div class="text-xs text-orange-900 leading-snug">${esc(penaltyDetailsStr)}</div>
                </div>` : ''}

                ${evRecReason ? `
                <div class="bg-slate-50 border border-slate-200 rounded-lg p-2.5 mb-3 flex gap-x-2">
                    <i class="fa-solid fa-gavel text-slate-500 mt-0.5 shrink-0"></i>
                    <div class="text-xs text-slate-700 leading-snug"><strong>Evaluation Recommendation Reason:</strong> ${esc(evRecReason)}</div>
                </div>` : ''}

                <!-- Dimension Scores + Radar -->
                <div class="flex items-center justify-between mb-2">
                    <div class="font-semibold text-sm">Dimension Scores</div>
                    <div class="text-[11px] text-slate-400">KTH Innovation Readiness Level (V-F 2025)</div>
                </div>
                <div class="grid lg:grid-cols-12 gap-4 items-center">
                    <div class="lg:col-span-5">
                        <canvas id="radarChart" height="180"></canvas>
                    </div>
                    <div class="lg:col-span-7">
                        <div class="grid grid-cols-4 gap-x-3 gap-y-1.5 text-xs">
                            <div class="flex justify-between border-b border-slate-100 pb-1"><span class="text-slate-500">TRL <span class="text-[9px] text-slate-400">(0.18)</span></span> <span class="font-mono font-semibold">${ev_trl}</span></div>
                            <div class="flex justify-between border-b border-slate-100 pb-1"><span class="text-slate-500">CRL <span class="text-[9px] text-slate-400">(0.22)</span></span> <span class="font-mono font-semibold">${ev_crl}</span></div>
                            <div class="flex justify-between border-b border-slate-100 pb-1"><span class="text-slate-500">BRL <span class="text-[9px] text-slate-400">(0.20)</span></span> <span class="font-mono font-semibold">${ev_brl}</span></div>
                            <div class="flex justify-between border-b border-slate-100 pb-1"><span class="text-slate-500">IPRL <span class="text-[9px] text-slate-400">(0.15)</span></span> <span class="font-mono font-semibold">${ev_iprl}</span></div>
                            <div class="flex justify-between border-b border-slate-100 pb-1"><span class="text-slate-500">TMRL <span class="text-[9px] text-slate-400">(0.15)</span></span> <span class="font-mono font-semibold">${ev_tmrl}</span></div>
                            <div class="flex justify-between border-b border-slate-100 pb-1"><span class="text-slate-500">FRL <span class="text-[9px] text-slate-400">(0.10)</span></span> <span class="font-mono font-semibold">${ev_frl}</span></div>
                        </div>
                    </div>
                </div>
            </div>
        </details>

        <!-- ==================== COMMERCIALIZATION STRATEGY ==================== -->
        <div class="bg-white border border-slate-200 rounded-xl p-4 mb-3">
            <div class="flex items-center gap-x-2 mb-3">
                <i class="fa-solid fa-lightbulb text-indigo-500"></i>
                <span class="font-semibold text-sm">Commercialization Strategy</span>
            </div>

            <!-- Value Proposition -->
            <div class="border border-indigo-100 rounded-lg p-3 mb-3 bg-indigo-50/30">
                <div class="text-[10px] uppercase tracking-wider text-indigo-600 font-semibold mb-1">Value Proposition</div>
                <div class="text-sm text-slate-800 leading-relaxed">${esc(valueProp)}</div>
            </div>

            <div class="grid lg:grid-cols-2 gap-3">
                <!-- Target Market -->
                <div class="border border-slate-200 rounded-lg p-3">
                    <div class="text-[10px] uppercase tracking-wider text-slate-400 mb-1"><i class="fa-solid fa-crosshairs mr-1"></i>Target Market Priority</div>
                    <div class="text-sm text-slate-700 leading-relaxed">${esc(targetMarket)}</div>
                </div>

                <!-- GTM Thesis -->
                <div class="border border-slate-200 rounded-lg p-3">
                    <div class="text-[10px] uppercase tracking-wider text-slate-400 mb-1"><i class="fa-solid fa-rocket mr-1"></i>Go-to-Market Thesis</div>
                    <div class="text-sm text-slate-700 leading-relaxed">${esc(gtmThesis)}</div>
                </div>

                <!-- Competitive Moat -->
                <div class="border border-slate-200 rounded-lg p-3">
                    <div class="text-[10px] uppercase tracking-wider text-slate-400 mb-1"><i class="fa-solid fa-shield-halved mr-1"></i>Competitive Moat Assessment</div>
                    <div class="text-sm text-slate-700 leading-relaxed">${esc(moatAssessment)}</div>
                </div>

                <!-- Regulatory Pathway -->
                <div class="border border-slate-200 rounded-lg p-3">
                    <div class="text-[10px] uppercase tracking-wider text-slate-400 mb-1"><i class="fa-solid fa-landmark mr-1"></i>Regulatory Pathway Summary</div>
                    <div class="text-sm text-slate-700 leading-relaxed">${esc(regPathway)}</div>
                </div>
            </div>

            <!-- Funding Strategy (full width) -->
            <div class="border border-slate-200 rounded-lg p-3 mt-3">
                <div class="text-[10px] uppercase tracking-wider text-slate-400 mb-1"><i class="fa-solid fa-coins mr-1"></i>Funding Strategy</div>
                <div class="text-sm text-slate-700 leading-relaxed">${esc(fundingStrat)}</div>
            </div>
        </div>

        <!-- ==================== RISK STRATIFICATION ==================== -->
        <div class="bg-white border border-slate-200 rounded-xl p-4 mb-3">
            <div class="flex items-center gap-x-2 mb-3">
                <i class="fa-solid fa-triangle-exclamation text-amber-500"></i>
                <span class="font-semibold text-sm">Risk Stratification</span>
            </div>
            <div class="grid lg:grid-cols-3 gap-3">
                <!-- Showstoppers -->
                <div class="border-2 ${showstoppers.length > 0 ? 'border-red-300 bg-red-50/30' : 'border-slate-200 bg-slate-50/30'} rounded-lg p-3">
                    <div class="flex items-center gap-x-1.5 text-red-600 mb-2">
                        <i class="fa-solid fa-skull-crossbones text-xs"></i>
                        <span class="text-xs font-semibold uppercase tracking-wider">Showstoppers</span>
                        <span class="ml-auto text-[10px] text-slate-400 font-normal">${showstoppers.length}</span>
                    </div>
                    ${buildRiskList(showstoppers, 'text-red-500')}
                </div>

                <!-- Material Risks -->
                <div class="border-2 ${materialRisks.length > 0 ? 'border-amber-300 bg-amber-50/30' : 'border-slate-200 bg-slate-50/30'} rounded-lg p-3">
                    <div class="flex items-center gap-x-1.5 text-amber-600 mb-2">
                        <i class="fa-solid fa-exclamation-circle text-xs"></i>
                        <span class="text-xs font-semibold uppercase tracking-wider">Material Risks</span>
                        <span class="ml-auto text-[10px] text-slate-400 font-normal">${materialRisks.length}</span>
                    </div>
                    ${buildRiskList(materialRisks, 'text-amber-500')}
                </div>

                <!-- Manageable Risks -->
                <div class="border-2 ${manageableRisks.length > 0 ? 'border-sky-300 bg-sky-50/30' : 'border-slate-200 bg-slate-50/30'} rounded-lg p-3">
                    <div class="flex items-center gap-x-1.5 text-sky-600 mb-2">
                        <i class="fa-solid fa-info-circle text-xs"></i>
                        <span class="text-xs font-semibold uppercase tracking-wider">Manageable Risks</span>
                        <span class="ml-auto text-[10px] text-slate-400 font-normal">${manageableRisks.length}</span>
                    </div>
                    ${buildRiskList(manageableRisks, 'text-sky-500')}
                </div>
            </div>
        </div>

        <!-- ==================== PRIORITIZED ACTIONS TABLE ==================== -->
        <div class="bg-white border border-slate-200 rounded-xl p-4 mb-3">
            <div class="flex items-center justify-between mb-3">
                <div class="flex items-center gap-x-2">
                    <i class="fa-solid fa-list-check text-indigo-500"></i>
                    <span class="font-semibold text-sm">Prioritized Action Roadmap</span>
                </div>
                <div class="flex gap-x-2">
                    <span class="px-2 py-0.5 text-[10px] font-semibold bg-red-50 text-red-700 rounded">${immCount} Immediate</span>
                    <span class="px-2 py-0.5 text-[10px] font-semibold bg-amber-50 text-amber-700 rounded">${shortCount} Short-term</span>
                    <span class="px-2 py-0.5 text-[10px] font-semibold bg-sky-50 text-sky-700 rounded">${medCount} Medium-term</span>
                </div>
            </div>
            <div class="overflow-x-auto">
                <table class="w-full text-xs border border-slate-200 rounded-lg overflow-hidden">
                    <thead>
                        <tr class="bg-slate-100 text-[10px] uppercase tracking-wider text-slate-500">
                            <th class="px-3 py-2 text-left font-normal w-8">#</th>
                            <th class="px-3 py-2 text-left font-normal">Action</th>
                            <th class="px-3 py-2 text-center font-normal w-36">Timeframe</th>
                            <th class="px-3 py-2 text-center font-normal w-20">Priority</th>
                            <th class="px-3 py-2 text-center font-normal w-28">Owner</th>
                            <th class="px-3 py-2 text-center font-normal w-32">Pillar</th>
                            <th class="px-3 py-2 text-left font-normal w-40">Dependencies</th>
                        </tr>
                    </thead>
                    <tbody>
                        ${actionRows || '<tr><td colspan="7" class="px-3 py-4 text-center text-slate-400 italic">No actions defined</td></tr>'}
                    </tbody>
                </table>
            </div>
        </div>

        <!-- ==================== STRENGTHS / GAPS ==================== -->
        <div class="grid lg:grid-cols-2 gap-2 mb-3">
            <div class="bg-white border border-emerald-200 rounded-xl p-3">
                <div class="flex items-center gap-x-1.5 text-emerald-600 mb-2 text-xs font-semibold uppercase tracking-wider">
                    <i class="fa-solid fa-check-circle"></i><span>Key Strengths</span>
                    <span class="ml-auto text-[10px] text-slate-400 font-normal">${strengths.length}</span>
                </div>
                <ul class="space-y-1.5 text-xs text-slate-600 leading-snug">
                    ${strengths.map(s => `<li class="flex gap-x-1.5"><span class="text-emerald-500 shrink-0">\u2022</span><span>${esc(s)}</span></li>`).join('')}
                </ul>
            </div>

            <div class="bg-white border border-red-200 rounded-xl p-3">
                <div class="flex items-center gap-x-1.5 text-red-600 mb-2 text-xs font-semibold uppercase tracking-wider">
                    <i class="fa-solid fa-exclamation-triangle"></i><span>Critical Gaps</span>
                    <span class="ml-auto text-[10px] text-slate-400 font-normal">${gaps.length}</span>
                </div>
                <ul class="space-y-1.5 text-xs text-slate-600 leading-snug">
                    ${gaps.map(g => `<li class="flex gap-x-1.5"><span class="text-red-500 shrink-0">\u2022</span><span>${esc(g)}</span></li>`).join('')}
                </ul>
            </div>
        </div>

        <!-- ==================== INVESTOR FRAMING ==================== -->
        ${investorFraming ? `
        <div class="bg-white border border-slate-200 rounded-xl p-3 mb-3">
            <div class="flex items-center gap-x-1.5 text-slate-600 mb-1">
                <i class="fa-solid fa-presentation-screen text-xs text-indigo-500"></i>
                <span class="text-[10px] uppercase tracking-wider font-semibold">Investor Framing Highlights</span>
            </div>
            <div class="text-slate-700 leading-relaxed text-xs">${esc(investorFraming)}</div>
        </div>` : ''}

        <!-- ==================== NOTES FOR HUMAN REVIEWER ==================== -->
        ${reviewerNotes ? `
        <div class="bg-slate-50 border border-slate-200 rounded-xl p-3 mb-3">
            <div class="flex items-center gap-x-1.5 text-slate-600 mb-1">
                <i class="fa-solid fa-clipboard-user text-xs"></i>
                <span class="text-[10px] uppercase tracking-wider font-semibold">Notes for Human Reviewer</span>
            </div>
            <div class="text-slate-700 leading-snug text-xs whitespace-pre-line">${esc(reviewerNotes)}</div>
        </div>` : ''}

    </div>

    <footer class="border-t border-slate-200 bg-white py-3 mt-3">
        <div class="max-w-screen-2xl mx-auto px-5 text-[11px] text-slate-400 flex justify-between">
            <div>Research Office \u2022 Project Team \u2022 Internal Review \u2022 Strategy Planning Agent v7b</div>
            <div>${esc(assessmentId)}</div>
        </div>
    </footer>

    <script>
        function initRadar() {
            var ctx = document.getElementById('radarChart');
            if (!ctx) return;

            new Chart(ctx, {
                type: 'radar',
                data: {
                    labels: ['TRL', 'CRL', 'BRL', 'IPRL', 'TMRL', 'FRL'],
                    datasets: [{
                        label: 'Score',
                        data: [${ev_trl}, ${ev_crl}, ${ev_brl}, ${ev_iprl}, ${ev_tmrl}, ${ev_frl}],
                        backgroundColor: 'rgba(15, 118, 110, 0.12)',
                        borderColor: '#0f766e',
                        borderWidth: 2,
                        pointBackgroundColor: '#0f766e',
                        pointRadius: 2.5
                    }]
                },
                options: {
                    responsive: true,
                    maintainAspectRatio: false,
                    scales: {
                        r: {
                            min: 0,
                            max: 9,
                            ticks: { stepSize: 3, color: '#64748b', font: { size: 9 } },
                            grid: { color: '#e2e8f0' },
                            angleLines: { color: '#cbd5e1' },
                            pointLabels: { color: '#334155', font: { size: 12, weight: 600 } }
                        }
                    },
                    plugins: { legend: { display: false } }
                }
            });
        }
        window.onload = initRadar;
    </script>
</body>
</html>`;

    return html;
}

// ============================================
// 5. SAVE
// ============================================
const htmlContent = generateReport(data, techCategory, savingPath);
const filename = `Strategy_Plan_${data.assessment_id || Date.now()}.html`;
const fullPath = path.join(savingPath, filename);

fs.writeFileSync(fullPath, htmlContent, 'utf8');
console.log('\u2705 Strategy Planning report (v7b \u2014 ground-truth metrics) saved to: ' + fullPath);
console.log('   Metrics sourced from: Merging All Research Items node (NOT AI agent output)');
console.log('   KTH Weighted Sum: ' + ev_kthSum + ' (pre-penalty) → ' + ev_penalizedSum + ' (penalized)');
console.log('   Dimension scores: TRL=' + ev_trl + ' CRL=' + ev_crl + ' BRL=' + ev_brl + ' IPRL=' + ev_iprl + ' TMRL=' + ev_tmrl + ' FRL=' + ev_frl);
console.log('   MRL=' + ev_mrl + '  Delta=' + ev_delta + '  TR=' + ev_trLevel + '  RRL=' + ev_rrl);
console.log('   Eval Recommendation: ' + evRecLabel);
console.log('   Strategy Pathway: ' + (data.strategic_recommendation?.pathway || 'N/A'));
console.log('   Actions: ' + (data.prioritized_actions || []).length + ' total');

return [{ json: { success: true, saved_path: fullPath, filename } }];

