parameters.jsCode:
const fs = require('fs');
const path = require('path');

const text = $input.first().json.redactedText ?? $('Text Cleaner').first().json.cleanedText;
const fileName = $input.first().json.fileName;
const cleanName = fileName.replace(/\.[^/.]+(?=$)/, "");
const basePath = $('Parse Form & Normalize Binary').first().json.base_path;
const outputDir = path.join(basePath, '02_Redacted');   // ← YOUR REQUIRED PATH

// === WRITE TO {base_path}/02_Redacted ===
fs.mkdirSync(outputDir, { recursive: true });

const safeFileName = `Redacted_${cleanName}.md`;
const outputPath = path.join(outputDir, safeFileName);

fs.writeFileSync(outputPath, text, 'utf8');

let message = `${safeFileName} generated`;

return {
  message: message
};
